import type { BibleVerse } from '../bibleData';

export const MATTHEW_CH15_28: Record<number, BibleVerse[]> = {
  15: [
    { v: 1, en: 'Then came to Jesus scribes and Pharisees, which were of Jerusalem, saying,', pt: 'Então os escribas e fariseus de Jerusalém aproximaram-se de Jesus, dizendo:' },
    { v: 2, en: 'Why do thy disciples transgress the tradition of the elders? for they wash not their hands when they eat bread.', pt: 'Por que transgridem os teus discípulos a tradição dos anciãos? Pois não lavam as mãos quando comem pão.' },
    { v: 3, en: 'But he answered and said unto them, Why do ye also transgress the commandment of God by your tradition?', pt: 'Ele, porém, respondeu: Por que também vós transgredis o mandamento de Deus por causa da vossa tradição?' },
    { v: 4, en: 'For God commanded, saying, Honour thy father and mother: and, He that curseth father or mother, let him die the death.', pt: 'Porque Deus ordenou: Honra teu pai e tua mãe; e: Quem amaldiçoar pai ou mãe, morra de morte.' },
    { v: 5, en: 'But ye say, Whosoever shall say to his father or his mother, It is a gift, by whatsoever thou mightest be profited by me;', pt: 'Vós, porém, dizeis: Quem disser ao pai ou à mãe: Aquilo com que te podia ajudar é uma oferta consagrada a Deus,' },
    { v: 6, en: 'And honour not his father or his mother, he shall be free. Thus have ye made the commandment of God of none effect by your tradition.', pt: 'Esse não precisa honrar seu pai ou sua mãe. E assim anulastes a palavra de Deus por causa da vossa tradição.' },
    { v: 7, en: 'Ye hypocrites, well did Esaias prophesy of you, saying,', pt: 'Hipócritas! Bem profetizou Isaías a vosso respeito, dizendo:' },
    { v: 8, en: 'This people draweth nigh unto me with their mouth, and honoureth me with their lips; but their heart is far from me.', pt: 'Este povo honra-me com os lábios, mas o seu coração está longe de mim.' },
    { v: 9, en: 'But in vain they do worship me, teaching for doctrines the commandments of men.', pt: 'Em vão, porém, me adoram, ensinando doutrinas que são preceitos de homens.' },
    { v: 10, en: 'And he called the multitude, and said unto them, Hear, and understand:', pt: 'E, chamando a multidão, disse-lhe: Ouvi e entendei:' },
    { v: 11, en: 'Not that which goeth into the mouth defileth a man; but that which cometh out of the mouth, this defileth a man.', pt: 'O que contamina o homem não é o que entra na boca; mas o que sai da boca, isso é o que o contamina.' },
    { v: 12, en: 'Then came his disciples, and said unto him, Knowest thou that the Pharisees were offended, after they heard this saying?', pt: 'Então os seus discípulos, aproximando-se, disseram-lhe: Sabes que os fariseus se escandalizaram ao ouvir esta palavra?' },
    { v: 13, en: 'But he answered and said, Every plant, which my heavenly Father hath not planted, shall be rooted up.', pt: 'Ele, porém, respondeu: Toda planta que meu Pai celestial não plantou será arrancada pela raiz.' },
    { v: 14, en: 'Let them alone: they be blind leaders of the blind. And if the blind lead the blind, both shall fall into the ditch.', pt: 'Deixai-os; são guias cegos de cegos; e, se um cego guiar outro cego, ambos cairão no barranco.' },
    { v: 15, en: 'Then answered Peter and said unto him, Declare unto us this parable.', pt: 'Então Pedro, respondendo, disse-lhe: Explica-nos esta parábola.' },
    { v: 16, en: 'And Jesus said, Are ye also yet without understanding?', pt: 'E Jesus disse: Ainda vós também sois sem entendimento?' },
    { v: 17, en: 'Do not ye yet understand, that whatsoever entereth in at the mouth goeth into the belly, and is cast out into the draught?', pt: 'Não entendeis ainda que tudo o que entra pela boca vai para o ventre e é lançado fora na privada?' },
    { v: 18, en: 'But those things which proceed out of the mouth come forth from the heart; and they defile the man.', pt: 'Mas as coisas que saem da boca procedem do coração, e estas contaminam o homem.' },
    { v: 19, en: 'For out of the heart proceed evil thoughts, murders, adulteries, fornications, thefts, false witness, blasphemies:', pt: 'Porque do coração procedem maus pensamentos, homicídios, adultérios, fornicações, furtos, falsos testemunhos, blasfêmias.' },
    { v: 20, en: 'These are the things which defile a man: but to eat with unwashen hands defileth not a man.', pt: 'Estas são as coisas que contaminam o homem; mas comer sem lavar as mãos não contamina o homem.' },
    { v: 21, en: 'Then Jesus went thence, and departed into the coasts of Tyre and Sidon.', pt: 'E, partindo Jesus dali, retirou-se para os lados de Tiro e Sidom.' },
    { v: 22, en: 'And, behold, a woman of Canaan came out of the same coasts, and cried unto him, saying, Have mercy on me, O Lord, thou son of David; my daughter is grievously vexed with a devil.', pt: 'E eis que uma mulher cananeia, saindo daquelas cercanias, clamou, dizendo: Senhor, Filho de Davi, tem misericórdia de mim! A minha filha está miseravelmente endemoninhada.' },
    { v: 23, en: 'But he answered her not a word. And his disciples came and besought him, saying, Send her away; for she crieth after us.', pt: 'Mas ele não lhe respondeu uma palavra. E os seus discípulos, chegando, rogaram-lhe: Despede-a, porque vem clamando atrás de nós.' },
    { v: 24, en: 'But he answered and said, I am not sent but unto the lost sheep of the house of Israel.', pt: 'Ele, porém, respondeu: Não fui enviado senão às ovelhas perdidas da casa de Israel.' },
    { v: 25, en: 'Then came she and worshipped him, saying, Lord, help me.', pt: 'Então ela veio e adorou-o, dizendo: Senhor, ajuda-me.' },
    { v: 26, en: 'But he answered and said, It is not meet to take the children\'s bread, and to cast it to dogs.', pt: 'E ele respondeu: Não é conveniente tomar o pão dos filhos e lançá-lo aos cachorrinhos.' },
    { v: 27, en: 'And she said, Truth, Lord: yet the dogs eat of the crumbs which fall from their masters\' table.', pt: 'Ela, porém, disse: Sim, Senhor, mas os cachorrinhos comem das migalhas que caem da mesa dos seus senhores.' },
    { v: 28, en: 'Then Jesus answered and said unto her, O woman, great is thy faith: be it unto thee even as thou wilt. And her daughter was made whole from that very hour.', pt: 'Então Jesus respondeu: Ó mulher, grande é a tua fé! Seja feito contigo como queres. E sua filha ficou sã desde aquela hora.' },
    { v: 29, en: 'And Jesus departed from thence, and came nigh unto the sea of Galilee; and went up into a mountain, and sat down there.', pt: 'E, partindo Jesus dali, veio para junto do mar da Galileia; e, subindo ao monte, assentou-se lá.' },
    { v: 30, en: 'And great multitudes came unto him, having with them those that were lame, blind, dumb, maimed, and many others, and cast them down at Jesus\' feet; and he healed them:', pt: 'E vieram a ele muitas multidões, trazendo consigo coxos, cegos, mudos, mancos e muitos outros, e os puseram aos seus pés, e ele os sarou.' },
    { v: 31, en: 'Insomuch that the multitude wondered, when they saw the dumb to speak, the maimed to be whole, the lame to walk, and the blind to see: and they glorified the God of Israel.', pt: 'De sorte que a multidão se admirou, vendo falar os mudos, sarar os mancos, andar os coxos e ver os cegos; e glorificaram o Deus de Israel.' },
    { v: 32, en: 'Then Jesus called his disciples unto him, and said, I have compassion on the multitude, because they continue with me now three days, and have nothing to eat: and I will not send them away fasting, lest they faint in the way.', pt: 'E Jesus, chamando os seus discípulos, disse: Tenho compaixão desta multidão, porque já há três dias que estão comigo e não têm o que comer; e não quero despedi-los em jejum, para que não desfaleçam no caminho.' },
    { v: 33, en: 'And his disciples say unto him, Whence should we have so much bread in the wilderness, as to fill so great a multitude?', pt: 'E os seus discípulos lhe disseram: De onde podemos nós ter tantos pães no deserto que saciem tão grande multidão?' },
    { v: 34, en: 'And Jesus saith unto them, How many loaves have ye? And they said, Seven, and a few little fishes.', pt: 'E Jesus lhes perguntou: Quantos pães tendes? E eles disseram: Sete, e alguns peixinhos.' },
    { v: 35, en: 'And he commanded the multitude to sit down on the ground.', pt: 'Então ordenou à multidão que se assentasse no chão.' },
    { v: 36, en: 'And he took the seven loaves and the fishes, and gave thanks, and brake them, and gave to his disciples, and the disciples to the multitude.', pt: 'E, tomando os sete pães e os peixes, dando graças, os partiu e os deu aos seus discípulos, e os discípulos à multidão.' },
    { v: 37, en: 'And they did all eat, and were filled: and they took up of the broken meat that was left seven baskets full.', pt: 'E todos comeram e se fartaram; e recolheram os pedaços que sobejaram, sete cestos cheios.' },
    { v: 38, en: 'And they that did eat were four thousand men, beside women and children.', pt: 'E os que comeram foram quatro mil homens, sem contar as mulheres e as crianças.' },
    { v: 39, en: 'And he sent away the multitude, and took ship, and came into the coasts of Magdala.', pt: 'E, despedindo a multidão, entrou no barco e foi para os confins de Magadã.' },
  ],
  16: [
    { v: 1, en: 'The Pharisees also with the Sadducees came, and tempting desired him that he would shew them a sign from heaven.', pt: 'E os fariseus e os saduceus, aproximando-se para tentá-lo, pediram-lhe que lhes mostrasse um sinal do céu.' },
    { v: 2, en: 'He answered and said unto them, When it is evening, ye say, It will be fair weather: for the sky is red.', pt: 'Ele, porém, respondeu: Quando é tarde, dizeis: Haverá bom tempo, pois o céu está vermelho.' },
    { v: 3, en: 'And in the morning, It will be foul weather to day: for the sky is red and lowring. O ye hypocrites, ye can discern the face of the sky; but can ye not discern the signs of the times?', pt: 'E de manhã: Hoje haverá tempestade, pois o céu está vermelho e carregado. Hipócritas! Sabeis discernir o aspecto do céu, mas não podeis discernir os sinais dos tempos?' },
    { v: 4, en: 'A wicked and adulterous generation seeketh after a sign; and there shall no sign be given unto it, but the sign of the prophet Jonas. And he left them, and departed.', pt: 'A geração má e adúltera pede um sinal, mas nenhum sinal lhe será dado senão o sinal do profeta Jonas. E, deixando-os, foi embora.' },
    { v: 5, en: 'And when his disciples were come to the other side, they had forgotten to take bread.', pt: 'E, passando os seus discípulos para a outra margem, esqueceram-se de trazer pão.' },
    { v: 6, en: 'Then Jesus said unto them, Take heed and beware of the leaven of the Pharisees and of the Sadducees.', pt: 'E Jesus lhes disse: Vede e guardai-vos do fermento dos fariseus e dos saduceus.' },
    { v: 7, en: 'And they reasoned among themselves, saying, It is because we have taken no bread.', pt: 'Então eles arrazoavam entre si, dizendo: É porque não trouxemos pão.' },
    { v: 8, en: 'Which when Jesus perceived, he said unto them, O ye of little faith, why reason ye among yourselves, because ye have brought no bread?', pt: 'E Jesus, percebendo isso, disse: Homens de pouca fé, por que arrazoais entre vós por não trazerdes pão?' },
    { v: 9, en: 'Do ye not yet understand, neither remember the five loaves of the five thousand, and how many baskets ye took up?', pt: 'Ainda não entendeis, nem vos lembrais dos cinco pães para cinco mil homens, e de quantos cestos recolhestes?' },
    { v: 10, en: 'Neither the seven loaves of the four thousand, and how many baskets ye took up?', pt: 'Nem dos sete pães para quatro mil homens, e de quantos cestos recolhestes?' },
    { v: 11, en: 'How is it that ye do not understand that I spake it not to you concerning bread, that ye should beware of the leaven of the Pharisees and of the Sadducees?', pt: 'Como é que não entendeis que não vos disse isso a respeito de pão? Mas guardai-vos do fermento dos fariseus e dos saduceus.' },
    { v: 12, en: 'Then understood they how that he bade them not beware of the leaven of bread, but of the doctrine of the Pharisees and of the Sadducees.', pt: 'Então entenderam eles que não disse que se guardassem do fermento do pão, mas da doutrina dos fariseus e dos saduceus.' },
    { v: 13, en: 'When Jesus came into the coasts of Caesarea Philippi, he asked his disciples, saying, Whom do men say that I the Son of man am?', pt: 'Quando Jesus veio às cercanias de Cesareia de Filipe, perguntou a seus discípulos: Quem dizem os homens ser o Filho do Homem?' },
    { v: 14, en: 'And they said, Some say that thou art John the Baptist: some, Elias; and others, Jeremias, or one of the prophets.', pt: 'E eles disseram: Uns dizem que é João Batista; outros, Elias; e outros, Jeremias ou um dos profetas.' },
    { v: 15, en: 'He saith unto them, But whom say ye that I am?', pt: 'Ele lhes disse: E vós, quem dizeis que eu sou?' },
    { v: 16, en: 'And Simon Peter answered and said, Thou art the Christ, the Son of the living God.', pt: 'Respondendo Simão Pedro, disse: Tu és o Cristo, o Filho do Deus vivo.' },
    { v: 17, en: 'And Jesus answered and said unto him, Blessed art thou, Simon Bar-jona: for flesh and blood hath not revealed it unto thee, but my Father which is in heaven.', pt: 'Respondendo Jesus, disse-lhe: Bem-aventurado és tu, Simão Barjonas, porque não te revelou isso a carne nem o sangue, mas meu Pai que está nos céus.' },
    { v: 18, en: 'And I say also unto thee, That thou art Peter, and upon this rock I will build my church; and the gates of hell shall not prevail against it.', pt: 'E eu também te digo que tu és Pedro, e sobre esta pedra edificarei a minha igreja, e as portas do inferno não prevalecerão contra ela.' },
    { v: 19, en: 'And I will give unto thee the keys of the kingdom of heaven: and whatsoever thou shalt bind on earth shall be bound in heaven: and whatsoever thou shalt loose on earth shall be loosed in heaven.', pt: 'E eu te darei as chaves do reino dos céus; e o que ligares na terra será ligado nos céus, e o que desligares na terra será desligado nos céus.' },
    { v: 20, en: 'Then charged he his disciples that they should tell no man that he was Jesus the Christ.', pt: 'Então ordenou aos seus discípulos que a ninguém dissessem que ele era Jesus o Cristo.' },
    { v: 21, en: 'From that time forth began Jesus to shew unto his disciples, how that he must go unto Jerusalem, and suffer many things of the elders and chief priests and scribes, and be killed, and be raised again the third day.', pt: 'Desde então começou Jesus a mostrar a seus discípulos que lhe era necessário ir a Jerusalém, e sofrer muitas coisas dos anciãos, e dos principais sacerdotes, e dos escribas, e ser morto, e ressuscitar ao terceiro dia.' },
    { v: 22, en: 'Then Peter took him, and began to rebuke him, saying, Be it far from thee, Lord: this shall not be unto thee.', pt: 'Então Pedro, chamando-o à parte, começou a reprová-lo, dizendo: Senhor, tem compaixão de ti; não te sucederá isso de modo nenhum.' },
    { v: 23, en: 'But he turned, and said unto Peter, Get thee behind me, Satan: thou art an offence unto me: for thou savourest not the things that be of God, but those that be of men.', pt: 'Mas ele, voltando-se, disse a Pedro: Arreda, Satanás; tu me és um escândalo, porque não cogitas as coisas de Deus, mas as dos homens.' },
    { v: 24, en: 'Then said Jesus unto his disciples, If any man will come after me, let him deny himself, and take up his cross, and follow me.', pt: 'Então Jesus disse a seus discípulos: Se alguém quiser vir após mim, renuncie-se a si mesmo, e tome a sua cruz, e siga-me.' },
    { v: 25, en: 'For whosoever will save his life shall lose it: and whosoever will lose his life for my sake shall find it.', pt: 'Porque quem quiser salvar a sua vida perdê-la-á, e quem perder a sua vida por amor de mim achá-la-á.' },
    { v: 26, en: 'For what is a man profited, if he shall gain the whole world, and lose his own soul? or what shall a man give in exchange for his soul?', pt: 'Porque que aproveitará ao homem ganhar o mundo inteiro, se perder a sua alma? Ou que dará o homem em troca da sua alma?' },
    { v: 27, en: 'For the Son of man shall come in the glory of his Father with his angels; and then he shall reward every man according to his works.', pt: 'Porque o Filho do Homem há de vir na glória de seu Pai com os seus anjos, e então retribuirá a cada um segundo as suas obras.' },
    { v: 28, en: 'Verily I say unto you, There be some standing here, which shall not taste of death, till they see the Son of man coming in his kingdom.', pt: 'Em verdade vos digo que alguns dos que aqui estão não provarão a morte até que vejam o Filho do Homem vindo no seu reino.' },
  ],
  17: [
    { v: 1, en: 'And after six days Jesus taketh Peter, James, and John his brother, and bringeth them up into an high mountain apart,', pt: 'E seis dias depois, Jesus tomou consigo a Pedro, Tiago e João seu irmão, e os levou a um alto monte, em particular.' },
    { v: 2, en: 'And was transfigured before them: and his face did shine as the sun, and his raiment was white as the light.', pt: 'E transfigurou-se diante deles; e o seu rosto resplandeceu como o sol, e as suas vestes se tornaram brancas como a luz.' },
    { v: 3, en: 'And, behold, there appeared unto them Moses and Elias talking with him.', pt: 'E eis que lhes apareceram Moisés e Elias, falando com ele.' },
    { v: 4, en: 'Then answered Peter, and said unto Jesus, Lord, it is good for us to be here: if thou wilt, let us make here three tabernacles; one for thee, and one for Moses, and one for Elias.', pt: 'E Pedro, respondendo, disse a Jesus: Senhor, bom é estarmos aqui; se queres, façamos aqui três tendas: uma para ti, uma para Moisés e uma para Elias.' },
    { v: 5, en: 'While he yet spake, behold, a bright cloud overshadowed them: and behold a voice out of the cloud, which said, This is my beloved Son, in whom I am well pleased; hear ye him.', pt: 'E ainda ele estava falando, quando uma nuvem resplandecente os cobriu; e eis que saiu uma voz da nuvem, que dizia: Este é o meu Filho amado, em quem me comprazo; a ele ouvi.' },
    { v: 6, en: 'And when the disciples heard it, they fell on their face, and were sore afraid.', pt: 'E os discípulos, ouvindo isso, caíram com o rosto em terra e ficaram muito atemorizados.' },
    { v: 7, en: 'And Jesus came and touched them, and said, Arise, and be not afraid.', pt: 'E Jesus, aproximando-se, tocou-os, dizendo: Levantai-vos e não tenhais medo.' },
    { v: 8, en: 'And when they had lifted up their eyes, they saw no man, save Jesus only.', pt: 'E, levantando eles os olhos, a ninguém viram senão a Jesus somente.' },
    { v: 9, en: 'And as they came down from the mountain, Jesus charged them, saying, Tell the vision to no man, until the Son of man be risen again from the dead.', pt: 'E, descendo eles do monte, Jesus lhes ordenou: A ninguém conteis esta visão até que o Filho do Homem seja ressuscitado dos mortos.' },
    { v: 10, en: 'And his disciples asked him, saying, Why then say the scribes that Elias must first come?', pt: 'E os seus discípulos lhe perguntaram: Por que dizem, pois, os escribas que é necessário que Elias venha primeiro?' },
    { v: 11, en: 'And Jesus answered and said unto them, Elias truly shall first come, and restore all things.', pt: 'E Jesus respondeu: Em verdade, Elias há de vir primeiro e restaurar todas as coisas.' },
    { v: 12, en: 'But I say unto you, That Elias is come already, and they knew him not, but have done unto him whatsoever they listed. Likewise shall also the Son of man suffer of them.', pt: 'Digo-vos, porém, que Elias já veio, e não o conheceram, mas fizeram-lhe tudo o que quiseram; assim também o Filho do Homem há de padecer nas mãos deles.' },
    { v: 13, en: 'Then the disciples understood that he spake unto them of John the Baptist.', pt: 'Então os discípulos entenderam que lhes falara acerca de João Batista.' },
    { v: 14, en: 'And when they were come to the multitude, there came to him a certain man, kneeling down to him, and saying,', pt: 'E, quando chegaram à multidão, aproximou-se dele um homem, ajoelhando-se diante dele e dizendo:' },
    { v: 15, en: 'Lord, have mercy on my son: for he is lunatick, and sore vexed: for ofttimes he falleth into the fire, and oft into the water.', pt: 'Senhor, tem misericórdia de meu filho, que é lunático e está muito mal, porque muitas vezes cai no fogo e muitas vezes na água.' },
    { v: 16, en: 'And I brought him to thy disciples, and they could not cure him.', pt: 'Trouxe-o aos teus discípulos, e eles não o puderam curar.' },
    { v: 17, en: 'Then Jesus answered and said, O faithless and perverse generation, how long shall I be with you? how long shall I suffer you? bring him hither to me.', pt: 'E Jesus respondeu: Ó geração incrédula e perversa! Até quando estarei convosco? Até quando vos sofrerei? Trazei-mo aqui.' },
    { v: 18, en: 'And Jesus rebuked the devil; and he departed out of him: and the child was cured from that very hour.', pt: 'E Jesus repreendeu o demônio, e ele saiu dele; e o menino ficou são desde aquela hora.' },
    { v: 19, en: 'Then came the disciples to Jesus apart, and said, Why could not we cast him out?', pt: 'Então os discípulos chegaram a Jesus em particular e disseram: Por que não pudemos nós expulsá-lo?' },
    { v: 20, en: 'And Jesus said unto them, Because of your unbelief: for verily I say unto you, If ye have faith as a grain of mustard seed, ye shall say unto this mountain, Remove hence to yonder place; and it shall remove; and nothing shall be impossible unto you.', pt: 'E Jesus disse-lhes: Por causa da vossa pouca fé; porque em verdade vos digo que, se tiverdes fé como um grão de mostarda, direis a este monte: Passa daqui para acolá, e ele passará; e nada vos será impossível.' },
    { v: 21, en: 'Howbeit this kind goeth not out but by prayer and fasting.', pt: 'Mas esta casta não sai senão pela oração e pelo jejum.' },
    { v: 22, en: 'And while they abode in Galilee, Jesus said unto them, The Son of man shall be betrayed into the hands of men:', pt: 'E, andando eles reunidos na Galileia, disse-lhes Jesus: O Filho do Homem está para ser entregue nas mãos dos homens.' },
    { v: 23, en: 'And they shall kill him, and the third day he shall be raised again. And they were exceeding sorry.', pt: 'E o matarão, mas ao terceiro dia ressuscitará. E eles ficaram muito tristes.' },
    { v: 24, en: 'And when they were come to Capernaum, they that received tribute money came to Peter, and said, Doth not your master pay tribute?', pt: 'E, quando chegaram a Cafarnaum, os que cobravam o tributo aproximaram-se de Pedro e disseram: O vosso mestre não paga o tributo?' },
    { v: 25, en: 'He saith, Yes. And when he was come into the house, Jesus prevented him, saying, What thinkest thou, Simon? of whom do the kings of the earth take custom or tribute? of their own children, or of strangers?', pt: 'Disse ele: Sim. E, entrando ele em casa, Jesus se antecipou, dizendo: Que te parece, Simão? Os reis da terra, de quem cobram os tributos ou o censo? De seus filhos, ou dos estranhos?' },
    { v: 26, en: 'Peter saith unto him, Of strangers. Jesus saith unto him, Then are the children free.', pt: 'E Pedro disse-lhe: Dos estranhos. Jesus disse-lhe: Logo os filhos são isentos.' },
    { v: 27, en: 'Notwithstanding, lest we should offend them, go thou to the sea, and cast an hook, and take up the fish that first cometh up; and when thou hast opened his mouth, thou shalt find a piece of money: that take, and give unto them for me and thee.', pt: 'Mas, para que não os escandalizemos, vai ao mar, lança o anzol, e o primeiro peixe que subir toma-o; e, abrindo-lhe a boca, acharás um estáter; toma-o e dá-o a eles por mim e por ti.' },
  ],
  18: [
    { v: 1, en: 'At the same time came the disciples unto Jesus, saying, Who is the greatest in the kingdom of heaven?', pt: 'Naquela hora, os discípulos chegaram a Jesus, dizendo: Quem é, pois, o maior no reino dos céus?' },
    { v: 2, en: 'And Jesus called a little child unto him, and set him in the midst of them,', pt: 'E Jesus, chamando um menino, o pôs no meio deles' },
    { v: 3, en: 'And said, Verily I say unto you, Except ye be converted, and become as little children, ye shall not enter into the kingdom of heaven.', pt: 'e disse: Em verdade vos digo que, se não vos converterdes e não vos tornardes como crianças, de modo algum entrareis no reino dos céus.' },
    { v: 4, en: 'Whosoever therefore shall humble himself as this little child, the same is greatest in the kingdom of heaven.', pt: 'Portanto, qualquer que se humilhar como esta criança, esse é o maior no reino dos céus.' },
    { v: 5, en: 'And whoso shall receive one such little child in my name receiveth me.', pt: 'E quem receber uma criança como esta em meu nome a mim me recebe.' },
    { v: 6, en: 'But whoso shall offend one of these little ones which believe in me, it were better for him that a millstone were hanged about his neck, and that he were drowned in the depth of the sea.', pt: 'Mas qualquer que escandalizar um destes pequeninos que creem em mim, melhor lhe fora que se lhe pendurasse ao pescoço uma pedra de moinho e fosse afogado na profundeza do mar.' },
    { v: 7, en: 'Woe unto the world because of offences! for it must needs be that offences come; but woe to that man by whom the offence cometh!', pt: 'Ai do mundo por causa dos escândalos! porque é necessário que os escândalos venham; mas ai daquele homem por quem vem o escândalo!' },
    { v: 8, en: 'Wherefore if thy hand or thy foot offend thee, cut them off, and cast them from thee: it is better for thee to enter into life halt or maimed, rather than having two hands or two feet to be cast into everlasting fire.', pt: 'Portanto, se a tua mão ou o teu pé te escandalizar, corta-o e lança-o de ti; melhor te é entrar na vida coxo ou mutilado do que, tendo duas mãos ou dois pés, seres lançado no fogo eterno.' },
    { v: 9, en: 'And if thine eye offend thee, pluck it out, and cast it from thee: it is better for thee to enter into life with one eye, rather than having two eyes to be cast into hell fire.', pt: 'E, se o teu olho te escandalizar, arranca-o e lança-o de ti; melhor te é entrar na vida com um olho do que, tendo dois olhos, seres lançado no fogo do inferno.' },
    { v: 10, en: 'Take heed that ye despise not one of these little ones; for I say unto you, That in heaven their angels do always behold the face of my Father which is in heaven.', pt: 'Vede que não desprezeis a nenhum destes pequeninos; porque vos digo que os seus anjos nos céus sempre veem a face de meu Pai que está nos céus.' },
    { v: 11, en: 'For the Son of man is come to save that which was lost.', pt: 'Porque o Filho do Homem veio salvar o que estava perdido.' },
    { v: 12, en: 'How think ye? if a man have an hundred sheep, and one of them be gone astray, doth he not leave the ninety and nine, and goeth into the mountains, and seeketh that which is gone astray?', pt: 'Que vos parece? Se um homem tiver cem ovelhas e uma delas se desgarrar, não deixará as noventa e nove nos montes e irá buscar a que se desgarrou?' },
    { v: 13, en: 'And if so be that he find it, verily I say unto you, he rejoiceth more of that sheep, than of the ninety and nine which went not astray.', pt: 'E, se porventura a achar, em verdade vos digo que mais se alegrará por ela do que pelas noventa e nove que não se desgarraram.' },
    { v: 14, en: 'Even so it is not the will of your Father which is in heaven, that one of these little ones should perish.', pt: 'Assim também não é da vontade de vosso Pai, que está nos céus, que se perca um destes pequeninos.' },
    { v: 15, en: 'Moreover if thy brother shall trespass against thee, go and tell him his fault between thee and him alone: if he shall hear thee, thou hast gained thy brother.', pt: 'E, se teu irmão pecar contra ti, vai e repreende-o entre ti e ele só; se te ouvir, ganhaste teu irmão.' },
    { v: 16, en: 'But if he will not hear thee, then take with thee one or two more, that in the mouth of two or three witnesses every word may be established.', pt: 'Mas, se não te ouvir, toma ainda contigo uma ou duas pessoas, para que pela boca de duas ou três testemunhas toda palavra seja confirmada.' },
    { v: 17, en: 'And if he shall neglect to hear them, tell it unto the church: but if he neglect to hear the church, let him be unto thee as an heathen man and a publican.', pt: 'E, se os não ouvir, dize-o à igreja; e, se também não ouvir a igreja, considera-o como um gentio e publicano.' },
    { v: 18, en: 'Verily I say unto you, Whatsoever ye shall bind on earth shall be bound in heaven: and whatsoever ye shall loose on earth shall be loosed in heaven.', pt: 'Em verdade vos digo que tudo o que ligardes na terra será ligado no céu, e tudo o que desligardes na terra será desligado no céu.' },
    { v: 19, en: 'Again I say unto you, That if two of you shall agree on earth as touching any thing that they shall ask, it shall be done for them of my Father which is in heaven.', pt: 'Digo-vos também que, se dois de vós concordarem na terra acerca de qualquer coisa que pedirem, isso lhes será feito por meu Pai que está nos céus.' },
    { v: 20, en: 'For where two or three are gathered together in my name, there am I in the midst of them.', pt: 'Porque onde estiverem dois ou três reunidos em meu nome, ali estou eu no meio deles.' },
    { v: 21, en: 'Then came Peter to him, and said, Lord, how oft shall my brother sin against me, and I forgive him? till seven times?', pt: 'Então Pedro aproximou-se dele e disse: Senhor, quantas vezes pecará meu irmão contra mim, e eu lhe perdoarei? Até sete vezes?' },
    { v: 22, en: 'Jesus saith unto him, I say not unto thee, Until seven times: but, Until seventy times seven.', pt: 'Jesus disse-lhe: Não te digo que até sete vezes, mas até setenta vezes sete.' },
    { v: 23, en: 'Therefore is the kingdom of heaven likened unto a certain king, which would take account of his servants.', pt: 'Por isso, o reino dos céus é semelhante a um rei que quis fazer contas com os seus servos.' },
    { v: 24, en: 'And when he had begun to reckon, one was brought unto him, which owed him ten thousand talents.', pt: 'E, quando começou a fazer contas, foi-lhe apresentado um que lhe devia dez mil talentos.' },
    { v: 25, en: 'But forasmuch as he had not to pay, his lord commanded him to be sold, and his wife, and children, and all that he had, and payment to be made.', pt: 'Não tendo este com que pagar, o seu senhor ordenou que fosse vendido ele, e sua mulher, e seus filhos, e tudo o que tinha, para ser paga a dívida.' },
    { v: 26, en: 'The servant therefore fell down, and worshipped him, saying, Lord, have patience with me, and I will pay thee all.', pt: 'Então aquele servo, prostrando-se, o reverenciava, dizendo: Senhor, tem paciência comigo, que eu te pagarei tudo.' },
    { v: 27, en: 'Then the lord of that servant was moved with compassion, and loosed him, and forgave him the debt.', pt: 'Então, movido de compaixão, o senhor daquele servo o soltou e lhe perdoou a dívida.' },
    { v: 28, en: 'But the same servant went out, and found one of his fellowservants, which owed him an hundred pence: and he laid hands on him, and took him by the throat, saying, Pay me that thou owest.', pt: 'Mas aquele servo, saindo, achou um dos seus conservos que lhe devia cem dinheiros e, lançando mão dele, o sufocava, dizendo: Paga-me o que me deves.' },
    { v: 29, en: 'And his fellowservant fell down at his feet, and besought him, saying, Have patience with me, and I will pay thee all.', pt: 'Então o seu conservo, prostrando-se aos seus pés, rogava-lhe: Tem paciência comigo, que eu te pagarei tudo.' },
    { v: 30, en: 'And he would not: but went and cast him into prison, till he should pay the debt.', pt: 'Ele, porém, não quis; antes foi e o lançou na prisão até que pagasse a dívida.' },
    { v: 31, en: 'So when his fellowservants saw what was done, they were very sorry, and came and told unto their lord all that was done.', pt: 'Vendo, pois, os seus conservos o que tinha acontecido, entristeceram-se muito e foram contar ao seu senhor tudo o que tinha sucedido.' },
    { v: 32, en: 'Then his lord, after that he had called him, said unto him, O thou wicked servant, I forgave thee all that debt, because thou desiredst me:', pt: 'Então o seu senhor, chamando-o, disse-lhe: Servo malvado, perdoei-te toda aquela dívida porque me suplicaste.' },
    { v: 33, en: 'Shouldest not thou also have had compassion on thy fellowservant, even as I had pity on thee?', pt: 'Não devias tu também ter compaixão do teu conservo, assim como eu tive misericórdia de ti?' },
    { v: 34, en: 'And his lord was wroth, and delivered him to the tormentors, till he should pay all that was due unto him.', pt: 'E, indignando-se, o seu senhor o entregou aos atormentadores, até que pagasse tudo o que devia.' },
    { v: 35, en: 'So likewise shall my heavenly Father do also unto you, if ye from your hearts forgive not every one his brother their trespasses.', pt: 'Assim também meu Pai celestial vos fará, se cada um de vós não perdoar de coração a seu irmão.' },
  ],
  19: [
    { v: 1, en: 'And it came to pass, that when Jesus had finished these sayings, he departed from Galilee, and came into the coasts of Judaea beyond Jordan;', pt: 'E aconteceu que, quando Jesus acabou estes discursos, partiu da Galileia e foi para os confins da Judeia, além do Jordão.' },
    { v: 2, en: 'And great multitudes followed him; and he healed them there.', pt: 'E grandes multidões o seguiram, e ele os curou ali.' },
    { v: 3, en: 'The Pharisees also came unto him, tempting him, and saying unto him, Is it lawful for a man to put away his wife for every cause?', pt: 'Então os fariseus, aproximando-se, tentaram-no, dizendo: É lícito ao homem repudiar sua mulher por qualquer motivo?' },
    { v: 4, en: 'And he answered and said unto them, Have ye not read, that he which made them at the beginning made them male and female,', pt: 'Ele, porém, respondeu: Não lestes que aquele que os criou desde o princípio os fez macho e fêmea' },
    { v: 5, en: 'And said, For this cause shall a man leave father and mother, and shall cleave to his wife: and they twain shall be one flesh?', pt: 'e disse: Por isso deixará o homem pai e mãe e se unirá à sua mulher, e os dois serão uma só carne?' },
    { v: 6, en: 'Wherefore they are no more twain, but one flesh. What therefore God hath joined together, let not man put asunder.', pt: 'De sorte que já não são dois, mas uma só carne. Portanto, o que Deus ajuntou não o separe o homem.' },
    { v: 7, en: 'They say unto him, Why did Moses then command to give a writing of divorcement, and to put her away?', pt: 'Disseram-lhe: Por que mandou, pois, Moisés dar carta de divórcio e repudiá-la?' },
    { v: 8, en: 'He saith unto them, Moses because of the hardness of your hearts suffered you to put away your wives: but from the beginning it was not so.', pt: 'Disse-lhes: Moisés, por causa da dureza do vosso coração, vos permitiu repudiar vossas mulheres; mas desde o princípio não foi assim.' },
    { v: 9, en: 'And I say unto you, Whosoever shall put away his wife, except it be for fornication, and shall marry another, committeth adultery: and whoso marrieth her which is put away doth commit adultery.', pt: 'E eu vos digo que qualquer que repudiar sua mulher, não sendo por causa de fornicação, e casar com outra, comete adultério; e o que casar com a repudiada também comete adultério.' },
    { v: 10, en: 'His disciples say unto him, If the case of the man be so with his wife, it is not good to marry.', pt: 'Disseram-lhe os seus discípulos: Se tal é a condição do homem em relação à mulher, não convém casar.' },
    { v: 11, en: 'But he said unto them, All men cannot receive this saying, save they to whom it is given.', pt: 'Ele, porém, disse-lhes: Nem todos recebem esta palavra, mas aqueles a quem isso é concedido.' },
    { v: 12, en: 'For there are some eunuchs, which were so born from their mother\'s womb: and there are some eunuchs, which were made eunuchs of men: and there be eunuchs, which have made themselves eunuchs for the kingdom of heaven\'s sake. He that is able to receive it, let him receive it.', pt: 'Porque há eunucos que nasceram assim do ventre da mãe; há eunucos que foram feitos eunucos pelos homens; e há eunucos que a si mesmos se fizeram eunucos por causa do reino dos céus. Quem pode receber isso, receba.' },
    { v: 13, en: 'Then were there brought unto him little children, that he should put his hands on them, and pray: and the disciples rebuked them.', pt: 'Então foram trazidos a ele uns meninos, para que lhes impusesse as mãos e orasse; e os discípulos os repreenderam.' },
    { v: 14, en: 'But Jesus said, Suffer little children, and forbid them not, to come unto me: for of such is the kingdom of heaven.', pt: 'Jesus, porém, disse: Deixai as crianças e não as impeçais de vir a mim, porque o reino dos céus pertence aos que são como elas.' },
    { v: 15, en: 'And he laid his hands on them, and departed thence.', pt: 'E, tendo-lhes imposto as mãos, partiu dali.' },
    { v: 16, en: 'And, behold, one came and said unto him, Good Master, what good thing shall I do, that I may have eternal life?', pt: 'E eis que um homem, aproximando-se, lhe disse: Mestre, que bem farei eu para ter a vida eterna?' },
    { v: 17, en: 'And he said unto him, Why callest thou me good? there is none good but one, that is, God: but if thou wilt enter into life, keep the commandments.', pt: 'E ele disse-lhe: Por que me perguntas acerca do bem? Só um há que é bom. Mas, se queres entrar na vida, guarda os mandamentos.' },
    { v: 18, en: 'He saith unto him, Which? Jesus said, Thou shalt do no murder, Thou shalt not commit adultery, Thou shalt not steal, Thou shalt not bear false witness,', pt: 'Disse-lhe ele: Quais? E Jesus disse: Não matarás, não adulterarás, não furtarás, não dirás falso testemunho,' },
    { v: 19, en: 'Honour thy father and thy mother: and, Thou shalt love thy neighbour as thyself.', pt: 'Honra teu pai e tua mãe; e: Amarás o teu próximo como a ti mesmo.' },
    { v: 20, en: 'The young man saith unto him, All these things have I kept from my youth up: what lack I yet?', pt: 'Disse-lhe o jovem: Tudo isso tenho guardado desde a minha juventude; que me falta ainda?' },
    { v: 21, en: 'Jesus said unto him, If thou wilt be perfect, go and sell that thou hast, and give to the poor, and thou shalt have treasure in heaven: and come and follow me.', pt: 'Jesus disse-lhe: Se queres ser perfeito, vai, vende os teus bens, dá-os aos pobres e terás um tesouro no céu; depois vem e segue-me.' },
    { v: 22, en: 'But when the young man heard that saying, he went away sorrowful: for he had great possessions.', pt: 'Ouvindo o jovem esta palavra, retirou-se triste, porque tinha muitos bens.' },
    { v: 23, en: 'Then said Jesus unto his disciples, Verily I say unto you, That a rich man shall hardly enter into the kingdom of heaven.', pt: 'Então disse Jesus a seus discípulos: Em verdade vos digo que é difícil um rico entrar no reino dos céus.' },
    { v: 24, en: 'And again I say unto you, It is easier for a camel to go through the eye of a needle, than for a rich man to enter into the kingdom of God.', pt: 'E ainda vos digo que é mais fácil passar um camelo pelo fundo de uma agulha do que entrar um rico no reino de Deus.' },
    { v: 25, en: 'When his disciples heard it, they were exceedingly amazed, saying, Who then can be saved?', pt: 'Ouvindo os seus discípulos isso, admiraram-se muito, dizendo: Quem pode, pois, salvar-se?' },
    { v: 26, en: 'But Jesus beheld them, and said unto them, With men this is impossible; but with God all things are possible.', pt: 'E Jesus, olhando para eles, disse-lhes: Aos homens isso é impossível, mas a Deus tudo é possível.' },
    { v: 27, en: 'Then answered Peter and said unto him, Behold, we have forsaken all, and followed thee; what shall we have therefore?', pt: 'Então Pedro, respondendo, lhe disse: Eis que nós deixamos tudo e te seguimos; que teremos nós, pois?' },
    { v: 28, en: 'And Jesus said unto them, Verily I say unto you, That ye which have followed me, in the regeneration when the Son of man shall sit in the throne of his glory, ye also shall sit upon twelve thrones, judging the twelve tribes of Israel.', pt: 'E Jesus disse-lhes: Em verdade vos digo que vós, que me seguistes, quando o Filho do Homem se assentar no trono da sua glória, na regeneração, também vos assentareis em doze tronos, julgando as doze tribos de Israel.' },
    { v: 29, en: 'And every one that hath forsaken houses, or brethren, or sisters, or father, or mother, or wife, or children, or lands, for my name\'s sake, shall receive an hundredfold, and shall inherit everlasting life.', pt: 'E todo aquele que tiver deixado casas, ou irmãos, ou irmãs, ou pai, ou mãe, ou mulher, ou filhos, ou campos por amor do meu nome, receberá cem vezes mais e herdará a vida eterna.' },
    { v: 30, en: 'But many that are first shall be last; and the last shall be first.', pt: 'Mas muitos primeiros serão últimos, e os últimos serão primeiros.' },
  ],
  20: [
    { v: 1, en: 'For the kingdom of heaven is like unto a man that is an householder, which went out early in the morning to hire labourers into his vineyard.', pt: 'Porque o reino dos céus é semelhante a um pai de família que saiu de madrugada a contratar trabalhadores para a sua vinha.' },
    { v: 2, en: 'And when he had agreed with the labourers for a penny a day, he sent them into his vineyard.', pt: 'E, ajustando com os trabalhadores um dinheiro por dia, mandou-os para a sua vinha.' },
    { v: 3, en: 'And he went out about the third hour, and saw others standing idle in the marketplace,', pt: 'E, saindo por volta da hora terceira, viu outros que estavam ociosos na praça' },
    { v: 4, en: 'And said unto them; Go ye also into the vineyard, and whatsoever is right I will give you. And they went their way.', pt: 'e disse-lhes: Ide vós também para a vinha, e dar-vos-ei o que for justo. E eles foram.' },
    { v: 5, en: 'Again he went out about the sixth and ninth hour, and did likewise.', pt: 'Saindo outra vez por volta da hora sexta e da nona, fez o mesmo.' },
    { v: 6, en: 'And about the eleventh hour he went out, and found others standing idle, and saith unto them, Why stand ye here all the day idle?', pt: 'E, saindo por volta da hora undécima, encontrou outros que estavam ociosos e disse-lhes: Por que estais aqui ociosos todo o dia?' },
    { v: 7, en: 'They say unto him, Because no man hath hired us. He saith unto them, Go ye also into the vineyard; and whatsoever is right, that shall ye receive.', pt: 'Disseram-lhe: Porque ninguém nos contratou. Ele lhes disse: Ide vós também para a vinha, e recebereis o que for justo.' },
    { v: 8, en: 'So when even was come, the lord of the vineyard saith unto his steward, Call the labourers, and give them their hire, beginning from the last unto the first.', pt: 'E, quando chegou a tarde, disse o senhor da vinha ao seu feitor: Chama os trabalhadores e paga-lhes o jornal, começando pelos últimos até aos primeiros.' },
    { v: 9, en: 'And when they came that were hired about the eleventh hour, they received every man a penny.', pt: 'E, chegando os da hora undécima, receberam cada um um dinheiro.' },
    { v: 10, en: 'But when the first came, they supposed that they should have received more; and they likewise received every man a penny.', pt: 'Quando chegaram os primeiros, supuseram que receberiam mais; mas também receberam cada um um dinheiro.' },
    { v: 11, en: 'And when they had received it, they murmured against the goodman of the house,', pt: 'E, recebendo-o, murmuravam contra o pai de família,' },
    { v: 12, en: 'Saying, These last have wrought but one hour, and thou hast made them equal unto us, which have borne the burden and heat of the day.', pt: 'dizendo: Estes últimos trabalharam apenas uma hora, e os igualaste a nós, que suportamos o peso do dia e o calor.' },
    { v: 13, en: 'But he answered one of them, and said, Friend, I do thee no wrong: didst not thou agree with me for a penny?', pt: 'Mas ele, respondendo a um deles, disse: Amigo, não te faço injustiça; não te ajustaste comigo por um dinheiro?' },
    { v: 14, en: 'Take that thine is, and go thy way: I will give unto this last, even as unto thee.', pt: 'Toma o que é teu e vai-te; mas quero dar a este último tanto quanto a ti.' },
    { v: 15, en: 'Is it not lawful for me to do what I will with mine own? Is thine eye evil, because I am good?', pt: 'Não me é lícito fazer o que quiser do que é meu? Ou é mau o teu olho porque eu sou bom?' },
    { v: 16, en: 'So the last shall be first, and the first last: for many be called, but few chosen.', pt: 'Assim, os últimos serão primeiros, e os primeiros serão últimos; porque muitos são chamados, mas poucos escolhidos.' },
    { v: 17, en: 'And Jesus going up to Jerusalem took the twelve disciples apart in the way, and said unto them,', pt: 'E, subindo Jesus a Jerusalém, chamou os doze discípulos em particular no caminho e disse-lhes:' },
    { v: 18, en: 'Behold, we go up to Jerusalem; and the Son of man shall be betrayed unto the chief priests and unto the scribes, and they shall condemn him to death,', pt: 'Eis que subimos a Jerusalém, e o Filho do Homem será entregue aos principais sacerdotes e aos escribas, e o condenarão à morte' },
    { v: 19, en: 'And shall deliver him to the Gentiles to mock, and to scourge, and to crucify him: and the third day he shall rise again.', pt: 'e o entregarão aos gentios para que o escarneçam, açoitem e crucifiquem; mas ao terceiro dia ressuscitará.' },
    { v: 20, en: 'Then came to him the mother of Zebedee\'s children with her sons, worshipping him, and desiring a certain thing of him.', pt: 'Então a mãe dos filhos de Zebedeu aproximou-se dele com seus filhos, adorando-o e pedindo-lhe alguma coisa.' },
    { v: 21, en: 'And he said unto her, What wilt thou? She saith unto him, Grant that these my two sons may sit, the one on thy right hand, and the other on the left, in thy kingdom.', pt: 'E ele lhe disse: Que queres? Ela disse: Ordena que estes meus dois filhos se assentem um à tua direita e outro à tua esquerda no teu reino.' },
    { v: 22, en: 'But Jesus answered and said, Ye know not what ye ask. Are ye able to drink of the cup that I shall drink of, and to be baptized with the baptism that I am baptized with? They say unto him, We are able.', pt: 'Jesus, porém, respondeu: Não sabeis o que pedis. Podeis vós beber do cálice que eu hei de beber, e ser batizados com o batismo com que eu sou batizado? Disseram-lhe: Podemos.' },
    { v: 23, en: 'And he saith unto them, Ye shall drink indeed of my cup, and be baptized with the baptism that I am baptized with: but to sit on my right hand, and on my left, is not mine to give, but it shall be given to them for whom it is prepared of my Father.', pt: 'E disse-lhes: Com efeito, bebereis do meu cálice e sereis batizados com o batismo com que eu sou batizado; mas assentar-vos à minha direita e à minha esquerda não é meu dar, mas é para aqueles a quem meu Pai o preparou.' },
    { v: 24, en: 'And when the ten heard it, they were moved with indignation against the two brethren.', pt: 'E os dez, ouvindo isso, indignou-se contra os dois irmãos.' },
    { v: 25, en: 'But Jesus called them unto him, and said, Ye know that the princes of the Gentiles exercise dominion over them, and they that are great exercise authority upon them.', pt: 'Mas Jesus, chamando-os, disse: Sabeis que os príncipes dos gentios os dominam, e que os grandes exercem sobre eles autoridade.' },
    { v: 26, en: 'But it shall not be so among you: but whosoever will be great among you, let him be your minister;', pt: 'Não será assim entre vós; mas qualquer que entre vós quiser tornar-se grande, esse será o que vos sirva.' },
    { v: 27, en: 'And whosoever will be chief among you, let him be your servant:', pt: 'E qualquer que entre vós quiser ser o primeiro, esse será vosso servo;' },
    { v: 28, en: 'Even as the Son of man came not to be ministered unto, but to minister, and to give his life a ransom for many.', pt: 'assim como o Filho do Homem não veio para ser servido, mas para servir e dar a sua vida em resgate de muitos.' },
    { v: 29, en: 'And as they departed from Jericho, a great multitude followed him.', pt: 'E, saindo eles de Jericó, seguiu-o grande multidão.' },
    { v: 30, en: 'And, behold, two blind men sitting by the way side, when they heard that Jesus passed by, cried out, saying, Have mercy on us, O Lord, thou son of David.', pt: 'E eis que dois cegos assentados à beira do caminho, ouvindo que Jesus passava, clamaram: Senhor, Filho de Davi, tem misericórdia de nós!' },
    { v: 31, en: 'And the multitude rebuked them, because they should hold their peace: but they cried the more, saying, Have mercy on us, O Lord, thou son of David.', pt: 'E a multidão os repreendeu para que se calassem; mas eles clamavam ainda mais: Senhor, Filho de Davi, tem misericórdia de nós!' },
    { v: 32, en: 'And Jesus stood still, and called them, and said, What will ye that I shall do unto you?', pt: 'E Jesus parou, chamou-os e disse: Que quereis que vos faça?' },
    { v: 33, en: 'They say unto him, Lord, that our eyes may be opened.', pt: 'Disseram-lhe: Senhor, que se abram os nossos olhos.' },
    { v: 34, en: 'So Jesus had compassion on them, and touched their eyes: and immediately their eyes received sight, and they followed him.', pt: 'E Jesus, compadecendo-se deles, tocou-lhes os olhos; e logo viram, e o seguiram.' },
  ],
  21: [
    { v: 1, en: 'And when they drew nigh unto Jerusalem, and were come to Bethphage, unto the mount of Olives, then sent Jesus two disciples,', pt: 'E, quando se aproximaram de Jerusalém e chegaram a Betfagé, ao monte das Oliveiras, Jesus enviou dois discípulos,' },
    { v: 2, en: 'Saying unto them, Go into the village over against you, and straightway ye shall find an ass tied, and a colt with her: loose them, and bring them unto me.', pt: 'dizendo-lhes: Ide à aldeia que está defronte de vós, e logo achareis uma jumenta presa e um jumentinho com ela; soltai-os e trazei-mos.' },
    { v: 3, en: 'And if any man say ought unto you, ye shall say, The Lord hath need of them; and straightway he will send them.', pt: 'E, se alguém vos disser alguma coisa, direis que o Senhor precisa deles; e logo os mandará.' },
    { v: 4, en: 'All this was done, that it might be fulfilled which was spoken by the prophet, saying,', pt: 'Tudo isso aconteceu para que se cumprisse o que foi dito pelo profeta:' },
    { v: 5, en: 'Tell ye the daughter of Sion, Behold, thy King cometh unto thee, meek, and sitting upon an ass, and a colt the foal of an ass.', pt: 'Dizei à filha de Sião: Eis que o teu Rei vem a ti, humilde, montado numa jumenta, num jumentinho, filho de animal de carga.' },
    { v: 6, en: 'And the disciples went, and did as Jesus commanded them,', pt: 'E os discípulos foram e fizeram como Jesus lhes ordenara.' },
    { v: 7, en: 'And brought the ass, and the colt, and put on them their clothes, and they set him thereon.', pt: 'E trouxeram a jumenta e o jumentinho, e puseram sobre eles as suas vestes, e ele se assentou em cima.' },
    { v: 8, en: 'And a very great multitude spread their garments in the way; others cut down branches from the trees, and strawed them in the way.', pt: 'E a maior parte da multidão estendia as suas vestes pelo caminho; e outros cortavam ramos das árvores e os espalhavam pelo caminho.' },
    { v: 9, en: 'And the multitudes that went before, and that followed, cried, saying, Hosanna to the son of David: Blessed is he that cometh in the name of the Lord; Hosanna in the highest.', pt: 'E as multidões que iam adiante e as que seguiam clamavam: Hosana ao Filho de Davi! Bendito o que vem em nome do Senhor! Hosana nas alturas!' },
    { v: 10, en: 'And when he was come into Jerusalem, all the city was moved, saying, Who is this?', pt: 'E, tendo ele entrado em Jerusalém, toda a cidade se agitou, dizendo: Quem é este?' },
    { v: 11, en: 'And the multitude said, This is Jesus the prophet of Nazareth of Galilee.', pt: 'E as multidões diziam: Este é Jesus, o profeta de Nazaré da Galileia.' },
    { v: 12, en: 'And Jesus went into the temple of God, and cast out all them that sold and bought in the temple, and overthrew the tables of the moneychangers, and the seats of them that sold doves,', pt: 'E Jesus entrou no templo de Deus e expulsou todos os que vendiam e compravam no templo, e derribou as mesas dos cambistas e as cadeiras dos que vendiam pombas.' },
    { v: 13, en: 'And said unto them, It is written, My house shall be called the house of prayer; but ye have made it a den of thieves.', pt: 'E disse-lhes: Está escrito: A minha casa será chamada casa de oração; mas vós a fazeis covil de ladrões.' },
    { v: 14, en: 'And the blind and the lame came to him in the temple; and he healed them.', pt: 'E chegaram a ele cegos e coxos no templo, e ele os sarou.' },
    { v: 15, en: 'And when the chief priests and scribes saw the wonderful things that he did, and the children crying in the temple, and saying, Hosanna to the son of David; they were sore displeased,', pt: 'E os principais sacerdotes e os escribas, vendo as maravilhas que ele fazia e as crianças que clamavam no templo: Hosana ao Filho de Davi! ficaram indignados' },
    { v: 16, en: 'And said unto him, Hearest thou what these say? And Jesus saith unto them, Yea; have ye never read, Out of the mouth of babes and sucklings thou hast perfected praise?', pt: 'e disseram-lhe: Ouves o que estes dizem? E Jesus disse-lhes: Sim; nunca lestes: Da boca de crianças e lactentes tiraste perfeito louvor?' },
    { v: 17, en: 'And he left them, and went out of the city into Bethany; and he lodged there.', pt: 'E, deixando-os, saiu da cidade para Betânia, e ali pousou.' },
    { v: 18, en: 'Now in the morning as he returned into the city, he hungered.', pt: 'Voltando de manhã para a cidade, teve fome.' },
    { v: 19, en: 'And when he saw a fig tree in the way, he came to it, and found nothing thereon, but leaves only, and said unto it, Let no fruit grow on thee henceforward for ever. And presently the fig tree withered away.', pt: 'E, vendo uma figueira junto ao caminho, chegou a ela e não achou nela coisa alguma senão folhas; e disse-lhe: Nunca mais nasça de ti fruto algum. E a figueira secou imediatamente.' },
    { v: 20, en: 'And when the disciples saw it, they marvelled, saying, How soon is the fig tree withered away!', pt: 'E os discípulos, vendo isso, admiraram-se, dizendo: Como secou imediatamente a figueira!' },
    { v: 21, en: 'Jesus answered and said unto them, Verily I say unto you, If ye have faith, and doubt not, ye shall not only do this which is done to the fig tree, but also if ye shall say unto this mountain, Be thou removed, and be thou cast into the sea; it shall be done.', pt: 'Jesus, porém, respondeu: Em verdade vos digo que, se tiverdes fé e não duvidardes, não somente fareis o que foi feito à figueira, mas, mesmo que disserdes a este monte: Levanta-te e lança-te no mar, isso se fará.' },
    { v: 22, en: 'And all things, whatsoever ye shall ask in prayer, believing, ye shall receive.', pt: 'E tudo o que pedirdes em oração, crendo, recebereis.' },
    { v: 23, en: 'And when he was come into the temple, the chief priests and the elders of the people came unto him as he was teaching, and said, By what authority doest thou these things? and who gave thee this authority?', pt: 'E, quando ele entrou no templo, os principais sacerdotes e os anciãos do povo aproximaram-se dele enquanto ensinava, e disseram: Por que autoridade fazes estas coisas? E quem te deu esta autoridade?' },
    { v: 24, en: 'And Jesus answered and said unto them, I also will ask you one thing, which if ye tell me, I in like wise will tell you by what authority I do these things.', pt: 'E Jesus respondeu: Também eu vos farei uma pergunta; se me responderdes, também eu vos direi por que autoridade faço estas coisas.' },
    { v: 25, en: 'The baptism of John, whence was it? from heaven, or of men? And they reasoned with themselves, saying, If we shall say, From heaven; he will say unto us, Why did ye not then believe him?', pt: 'O batismo de João, de onde era? Do céu ou dos homens? E eles arrazoavam consigo: Se dissermos: Do céu, ele nos dirá: Por que, pois, não crestes nele?' },
    { v: 26, en: 'But if we shall say, Of men; we fear the people; for all hold John as a prophet.', pt: 'E, se dissermos: Dos homens, tememos a multidão, porque todos têm João por profeta.' },
    { v: 27, en: 'And they answered Jesus, and said, We cannot tell. And he said unto them, Neither tell I you by what authority I do these things.', pt: 'E responderam a Jesus: Não sabemos. E ele lhes disse: Também eu não vos digo por que autoridade faço estas coisas.' },
    { v: 28, en: 'But what think ye? A certain man had two sons; and he came to the first, and said, Son, go work to day in my vineyard.', pt: 'Mas que vos parece? Um homem tinha dois filhos, e, chegando ao primeiro, disse: Filho, vai trabalhar hoje na vinha.' },
    { v: 29, en: 'He answered and said, I will not: but afterward he repented, and went.', pt: 'E ele respondeu: Não quero; mas depois se arrependeu e foi.' },
    { v: 30, en: 'And he came to the second, and said likewise. And he answered and said, I go, sir: and went not.', pt: 'E, chegando ao segundo, disse o mesmo. E ele respondeu: Eu irei, senhor; mas não foi.' },
    { v: 31, en: 'Whether of them twain did the will of his father? They say unto him, The first. Jesus saith unto them, Verily I say unto you, That the publicans and the harlots go into the kingdom of God before you.', pt: 'Qual dos dois fez a vontade do pai? Disseram-lhe: O primeiro. Jesus disse-lhes: Em verdade vos digo que os publicanos e as meretrizes entram primeiro do que vós no reino de Deus.' },
    { v: 32, en: 'For John came unto you in the way of righteousness, and ye believed him not: but the publicans and the harlots believed him: and ye, when ye had seen it, repented not afterward, that ye might believe him.', pt: 'Porque João veio a vós no caminho da justiça, e não crestes nele; mas os publicanos e as meretrizes creram nele; e vós, ainda depois de o verdes, não vos arrependestes para nele crer.' },
    { v: 33, en: 'Hear another parable: There was a certain householder, which planted a vineyard, and hedged it round about, and digged a winepress in it, and built a tower, and let it out to husbandmen, and went into a far country:', pt: 'Ouvi outra parábola: Havia certo homem, pai de família, que plantou uma vinha e a cercou com uma sebe, e cavou nela um lagar, e edificou uma torre, e arrendou-a a lavradores, e viajou para longe.' },
    { v: 34, en: 'And when the time of the fruit drew near, he sent his servants to the husbandmen, that they might receive the fruits of it.', pt: 'E, chegando o tempo dos frutos, enviou os seus servos aos lavradores, para receber os seus frutos.' },
    { v: 35, en: 'And the husbandmen took his servants, and beat one, and killed another, and stoned another.', pt: 'E os lavradores, agarrando os seus servos, espancaram um, mataram outro e apedrejaram outro.' },
    { v: 36, en: 'Again, he sent other servants more than the first: and they did unto them likewise.', pt: 'De novo enviou outros servos, em maior número do que os primeiros; e fizeram-lhes o mesmo.' },
    { v: 37, en: 'But last of all he sent unto them his son, saying, They will reverence my son.', pt: 'Por fim enviou-lhes o seu filho, dizendo: Terão respeito a meu filho.' },
    { v: 38, en: 'But when the husbandmen saw the son, they said among themselves, This is the heir; come, let us kill him, and let us seize on his inheritance.', pt: 'Mas os lavradores, quando viram o filho, disseram entre si: Este é o herdeiro; vinde, matemo-lo, e apoderemo-nos da sua herança.' },
    { v: 39, en: 'And they caught him, and cast him out of the vineyard, and slew him.', pt: 'E, agarrando-o, lançaram-no fora da vinha e o mataram.' },
    { v: 40, en: 'When the lord therefore of the vineyard cometh, what will he do unto those husbandmen?', pt: 'Quando, pois, vier o senhor da vinha, que fará a esses lavradores?' },
    { v: 41, en: 'They say unto him, He will miserably destroy those wicked men, and will let out his vineyard unto other husbandmen, which shall render him the fruits in their seasons.', pt: 'Disseram-lhe: Matará cruelmente a esses malfeitores e arrendará a vinha a outros lavradores, que lhe entreguem os frutos a seus tempos.' },
    { v: 42, en: 'Jesus saith unto them, Did ye never read in the scriptures, The stone which the builders rejected, the same is become the head of the corner: this is the Lord\'s doing, and it is marvellous in our eyes?', pt: 'Jesus disse-lhes: Nunca lestes nas Escrituras: A pedra que os edificadores rejeitaram, essa foi posta como pedra angular; isso veio do Senhor e é maravilhoso aos nossos olhos?' },
    { v: 43, en: 'Therefore say I unto you, The kingdom of God shall be taken from you, and given to a nation bringing forth the fruits thereof.', pt: 'Por isso vos digo que o reino de Deus vos será tirado, e será dado a uma nação que produza os seus frutos.' },
    { v: 44, en: 'And whosoever shall fall on this stone shall be broken: but on whomsoever it shall fall, it will grind him to powder.', pt: 'E todo aquele que cair sobre esta pedra será quebrado; mas sobre quem ela cair, o reduzirá a pó.' },
    { v: 45, en: 'And when the chief priests and Pharisees had heard his parables, they perceived that he spake of them.', pt: 'E os principais sacerdotes e os fariseus, ouvindo as suas parábolas, entenderam que falava deles.' },
    { v: 46, en: 'But when they sought to lay hands on him, they feared the multitude, because they took him for a prophet.', pt: 'E, procurando prendê-lo, temeram a multidão, pois o tinham como profeta.' },
  ],
  22: [
    { v: 1, en: 'And Jesus answered and spake unto them again by parables, and said,', pt: 'E Jesus, respondendo, tornou a falar-lhes por parábolas, dizendo:' },
    { v: 2, en: 'The kingdom of heaven is like unto a certain king, which made a marriage for his son,', pt: 'O reino dos céus é semelhante a um rei que fez as bodas de seu filho.' },
    { v: 3, en: 'And sent forth his servants to call them that were bidden to the wedding: and they would not come.', pt: 'E enviou os seus servos para chamarem os convidados para as bodas; mas eles não quiseram vir.' },
    { v: 4, en: 'Again, he sent forth other servants, saying, Tell them which are bidden, Behold, I have prepared my dinner: my oxen and my fatlings are killed, and all things are ready: come unto the marriage.', pt: 'Tornou a enviar outros servos, dizendo: Dizei aos convidados: Eis que já preparei o meu jantar; os meus bois e os animais cevados já estão mortos, e tudo está pronto; vinde às bodas.' },
    { v: 5, en: 'But they made light of it, and went their ways, one to his farm, another to his merchandise:', pt: 'Eles, porém, não fizeram caso e foram, um para o seu campo, outro para o seu negócio;' },
    { v: 6, en: 'And the remnant took his servants, and entreated them spitefully, and slew them.', pt: 'e os restantes, agarrando os seus servos, os maltrataram e os mataram.' },
    { v: 7, en: 'But when the king heard thereof, he was wroth: and he sent forth his armies, and destroyed those murderers, and burned up their city.', pt: 'E o rei, ouvindo isso, ficou irado; e, enviando os seus exércitos, destruiu aqueles homicidas e incendiou a sua cidade.' },
    { v: 8, en: 'Then saith he to his servants, The wedding is ready, but they which were bidden were not worthy.', pt: 'Então disse aos seus servos: As bodas estão preparadas; mas os convidados não eram dignos.' },
    { v: 9, en: 'Go ye therefore into the highways, and as many as ye shall find, bid to the marriage.', pt: 'Ide, pois, às encruzilhadas dos caminhos e convidai para as bodas todos quantos encontrardes.' },
    { v: 10, en: 'So those servants went out into the highways, and gathered together all as many as they found, both bad and good: and the wedding was furnished with guests.', pt: 'E os servos saíram pelos caminhos e reuniram todos os que encontraram, tanto maus como bons; e a sala das bodas se encheu de convidados.' },
    { v: 11, en: 'And when the king came in to see the guests, he saw there a man which had not on a wedding garment:', pt: 'E, entrando o rei para ver os convidados, viu ali um homem que não estava vestido com veste de bodas;' },
    { v: 12, en: 'And he saith unto him, Friend, how camest thou in hither not having a wedding garment? And he was speechless.', pt: 'e disse-lhe: Amigo, como entraste aqui sem veste de bodas? E ele emudeceu.' },
    { v: 13, en: 'Then said the king to the servants, Bind him hand and foot, and take him away, and cast him into outer darkness; there shall be weeping and gnashing of teeth.', pt: 'Então o rei disse aos servos: Amarrai-o de pés e mãos, e lançai-o nas trevas exteriores; ali haverá choro e ranger de dentes.' },
    { v: 14, en: 'For many are called, but few are chosen.', pt: 'Porque muitos são chamados, mas poucos escolhidos.' },
    { v: 15, en: 'Then went the Pharisees, and took counsel how they might entangle him in his talk.', pt: 'Então os fariseus foram e deliberaram como o apanhariam em alguma palavra.' },
    { v: 16, en: 'And they sent out unto him their disciples with the Herodians, saying, Master, we know that thou art true, and teachest the way of God in truth, neither carest thou for any man: for thou regardest not the person of men.', pt: 'E enviaram-lhe os seus discípulos com os herodianos, dizendo: Mestre, sabemos que és verdadeiro e que ensinas o caminho de Deus em verdade, e não te importas com ninguém, porque não olhas a aparência das pessoas.' },
    { v: 17, en: 'Tell us therefore, What thinkest thou? Is it lawful to give tribute unto Caesar, or not?', pt: 'Dize-nos, pois, que te parece: É lícito dar tributo a César, ou não?' },
    { v: 18, en: 'But Jesus perceived their wickedness, and said, Why tempt ye me, ye hypocrites?', pt: 'Mas Jesus, conhecendo a malícia deles, disse: Por que me tentais, hipócritas?' },
    { v: 19, en: 'Shew me the tribute money. And they brought unto him a penny.', pt: 'Mostrai-me a moeda do tributo. E eles lhe apresentaram um dinheiro.' },
    { v: 20, en: 'And he saith unto them, Whose is this image and superscription?', pt: 'E ele disse-lhes: De quem é esta imagem e esta inscrição?' },
    { v: 21, en: 'They say unto him, Caesar\'s. Then saith he unto them, Render therefore unto Caesar the things which are Caesar\'s; and unto God the things that are God\'s.', pt: 'Disseram-lhe: De César. Então ele lhes disse: Dai, pois, a César o que é de César e a Deus o que é de Deus.' },
    { v: 22, en: 'When they had heard these words, they marvelled, and left him, and went their way.', pt: 'E, ouvindo isso, maravilharam-se, e, deixando-o, foram-se.' },
    { v: 23, en: 'The same day came to him the Sadducees, which say that there is no resurrection, and asked him,', pt: 'Naquele mesmo dia, aproximaram-se dele os saduceus, que dizem não haver ressurreição, e perguntaram-lhe,' },
    { v: 24, en: 'Saying, Master, Moses said, If a man die, having no children, his brother shall marry his wife, and raise up seed unto his brother.', pt: 'dizendo: Mestre, Moisés disse: Se alguém morrer sem filhos, o seu irmão casará com a sua mulher e suscitará descendência ao seu irmão.' },
    { v: 25, en: 'Now there were with us seven brethren: and the first, when he had married a wife, deceased, and, having no issue, left his wife unto his brother:', pt: 'Havia entre nós sete irmãos: o primeiro casou e morreu; e, não tendo descendência, deixou a sua mulher ao seu irmão.' },
    { v: 26, en: 'Likewise the second also, and the third, unto the seventh.', pt: 'Da mesma forma o segundo, e o terceiro, até ao sétimo.' },
    { v: 27, en: 'And last of all the woman died also.', pt: 'E, por último, a mulher também morreu.' },
    { v: 28, en: 'Therefore in the resurrection whose wife shall she be of the seven? for they all had her.', pt: 'Na ressurreição, pois, de qual dos sete será ela mulher, visto que todos a tiveram?' },
    { v: 29, en: 'Jesus answered and said unto them, Ye do err, not knowing the scriptures, nor the power of God.', pt: 'E Jesus, respondendo, disse-lhes: Errais, não conhecendo as Escrituras nem o poder de Deus.' },
    { v: 30, en: 'For in the resurrection they neither marry, nor are given in marriage, but are as the angels of God in heaven.', pt: 'Porque na ressurreição nem casam nem se dão em casamento, mas são como os anjos de Deus no céu.' },
    { v: 31, en: 'But as touching the resurrection of the dead, have ye not read that which was spoken unto you by God, saying,', pt: 'E quanto à ressurreição dos mortos, não lestes o que vos foi dito por Deus:' },
    { v: 32, en: 'I am the God of Abraham, and the God of Isaac, and the God of Jacob? God is not the God of the dead, but of the living.', pt: 'Eu sou o Deus de Abraão, e o Deus de Isaque, e o Deus de Jacó? Deus não é o Deus dos mortos, mas dos vivos.' },
    { v: 33, en: 'And when the multitude heard this, they were astonished at his doctrine.', pt: 'E as multidões, ouvindo isso, ficaram admiradas com a sua doutrina.' },
    { v: 34, en: 'But when the Pharisees had heard that he had put the Sadducees to silence, they were gathered together.', pt: 'E os fariseus, ouvindo que ele havia fechado a boca aos saduceus, reuniram-se.' },
    { v: 35, en: 'Then one of them, which was a lawyer, asked him a question, tempting him, and saying,', pt: 'E um deles, doutor da lei, perguntou-lhe para o tentar:' },
    { v: 36, en: 'Master, which is the great commandment in the law?', pt: 'Mestre, qual é o grande mandamento na lei?' },
    { v: 37, en: 'Jesus said unto him, Thou shalt love the Lord thy God with all thy heart, and with all thy soul, and with all thy mind.', pt: 'E Jesus disse-lhe: Amarás o Senhor teu Deus de todo o teu coração, e de toda a tua alma, e de todo o teu pensamento.' },
    { v: 38, en: 'This is the first and great commandment.', pt: 'Este é o primeiro e grande mandamento.' },
    { v: 39, en: 'And the second is like unto it, Thou shalt love thy neighbour as thyself.', pt: 'E o segundo, semelhante a este, é: Amarás o teu próximo como a ti mesmo.' },
    { v: 40, en: 'On these two commandments hang all the law and the prophets.', pt: 'Destes dois mandamentos dependem toda a lei e os profetas.' },
    { v: 41, en: 'While the Pharisees were gathered together, Jesus asked them,', pt: 'E, estando os fariseus reunidos, Jesus perguntou-lhes:' },
    { v: 42, en: 'Saying, What think ye of Christ? whose son is he? They say unto him, The son of David.', pt: 'Que vos parece do Cristo? De quem é filho? Disseram-lhe: De Davi.' },
    { v: 43, en: 'He saith unto them, How then doth David in spirit call him Lord, saying,', pt: 'Disse-lhes ele: Como, pois, Davi, em espírito, lhe chama Senhor, dizendo:' },
    { v: 44, en: 'The LORD said unto my Lord, Sit thou on my right hand, till I make thine enemies thy footstool?', pt: 'Disse o Senhor ao meu Senhor: Assenta-te à minha direita, até que eu ponha os teus inimigos debaixo dos teus pés?' },
    { v: 45, en: 'If David then call him Lord, how is he his son?', pt: 'Se Davi, pois, lhe chama Senhor, como é ele seu filho?' },
    { v: 46, en: 'And no man was able to answer him a word, neither durst any man from that day forth ask him any more questions.', pt: 'E ninguém lhe pôde responder uma palavra; nem ousou alguém, desde aquele dia, fazer-lhe mais perguntas.' },
  ],
  23: [
    { v: 1, en: 'Then spake Jesus to the multitude, and to his disciples,', pt: 'Então Jesus falou às multidões e aos seus discípulos,' },
    { v: 2, en: 'Saying, The scribes and the Pharisees sit in Moses\' seat:', pt: 'dizendo: Os escribas e os fariseus assentaram-se na cadeira de Moisés.' },
    { v: 3, en: 'All therefore whatsoever they bid you observe, that observe and do; but do not ye after their works: for they say, and do not.', pt: 'Portanto, tudo o que eles vos disserem que observeis, observai e fazei; mas não façais segundo as suas obras, porque dizem e não fazem.' },
    { v: 4, en: 'For they bind heavy burdens and grievous to be borne, and lay them on men\'s shoulders; but they themselves will not move them with one of their fingers.', pt: 'Porque atam fardos pesados e difíceis de carregar e os põem nos ombros dos homens, mas eles mesmos não os querem mover nem sequer com um dedo.' },
    { v: 5, en: 'But all their works they do for to be seen of men: they make broad their phylacteries, and enlarge the borders of their garments,', pt: 'E fazem todas as suas obras para serem vistos pelos homens; porque alargam os seus filactérios e aumentam as franjas dos seus mantos;' },
    { v: 6, en: 'And love the uppermost rooms at feasts, and the chief seats in the synagogues,', pt: 'e amam os primeiros lugares nos banquetes e as primeiras cadeiras nas sinagogas,' },
    { v: 7, en: 'And greetings in the markets, and to be called of men, Rabbi, Rabbi.', pt: 'e as saudações nas praças, e ser chamados pelos homens: Rabi, Rabi.' },
    { v: 8, en: 'But be not ye called Rabbi: for one is your Master, even Christ; and all ye are brethren.', pt: 'Mas vós não queirais ser chamados Rabi, porque um só é o vosso Mestre, e todos vós sois irmãos.' },
    { v: 9, en: 'And call no man your father upon the earth: for one is your Father, which is in heaven.', pt: 'E a ninguém na terra chameis vosso pai, porque um só é o vosso Pai, o qual está nos céus.' },
    { v: 10, en: 'Neither be ye called masters: for one is your Master, even Christ.', pt: 'Nem vos deixeis chamar mestres, porque um só é o vosso Mestre, Cristo.' },
    { v: 11, en: 'But he that is greatest among you shall be your servant.', pt: 'Mas o maior entre vós será vosso servo.' },
    { v: 12, en: 'And whosoever shall exalt himself shall be abased; and he that shall humble himself shall be exalted.', pt: 'E aquele que se exaltar será humilhado, e aquele que se humilhar será exaltado.' },
    { v: 13, en: 'But woe unto you, scribes and Pharisees, hypocrites! for ye shut up the kingdom of heaven against men: for ye neither go in yourselves, neither suffer ye them that are entering to go in.', pt: 'Mas ai de vós, escribas e fariseus, hipócritas! Porque fechais o reino dos céus diante dos homens; pois não entrais vós, nem deixais entrar os que estão entrando.' },
    { v: 14, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye devour widows\' houses, and for a pretence make long prayer: therefore ye shall receive the greater damnation.', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque devorais as casas das viúvas e fazeis longas orações por pretexto; por isso recebereis maior condenação.' },
    { v: 15, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye compass sea and land to make one proselyte, and when he is made, ye make him twofold more the child of hell than yourselves.', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque percorreis o mar e a terra para fazer um prosélito, e quando o fazeis o tornais dois vezes mais filho do inferno do que vós.' },
    { v: 16, en: 'Woe unto you, ye blind guides, which say, Whosoever shall swear by the temple, it is nothing; but whosoever shall swear by the gold of the temple, he is a debtor!', pt: 'Ai de vós, guias cegos! que dizeis: Se alguém jurar pelo templo, não é nada; mas se alguém jurar pelo ouro do templo, fica obrigado.' },
    { v: 17, en: 'Ye fools and blind: for whether is greater, the gold, or the temple that sanctifieth the gold?', pt: 'Insensatos e cegos! Porque qual é maior, o ouro, ou o templo que santifica o ouro?' },
    { v: 18, en: 'And, Whosoever shall swear by the altar, it is nothing; but whosoever sweareth by the gift that is upon it, he is guilty.', pt: 'E: Se alguém jurar pelo altar, não é nada; mas se alguém jurar pela oferta que está sobre ele, fica obrigado.' },
    { v: 19, en: 'Ye fools and blind: for whether is greater, the gift, or the altar that sanctifieth the gift?', pt: 'Insensatos e cegos! Porque qual é maior, a oferta, ou o altar que santifica a oferta?' },
    { v: 20, en: 'Whoso therefore shall swear by the altar, sweareth by it, and by all things thereon.', pt: 'Portanto, quem jurar pelo altar, jura por ele e por tudo o que está sobre ele.' },
    { v: 21, en: 'And whoso shall swear by the temple, sweareth by it, and by him that dwelleth therein.', pt: 'E quem jurar pelo templo, jura por ele e por aquele que nele habita.' },
    { v: 22, en: 'And he that shall swear by heaven, sweareth by the throne of God, and by him that sitteth thereon.', pt: 'E quem jurar pelo céu, jura pelo trono de Deus e por aquele que nele se assenta.' },
    { v: 23, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye pay tithe of mint and anise and cummin, and have omitted the weightier matters of the law, judgment, mercy, and faith: these ought ye to have done, and not to leave the other undone.', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque dizimais a hortelã, o endro e o cominho, e tendes deixado o mais importante da lei: o juízo, a misericórdia e a fidelidade; estas coisas deveis fazer, sem omitir aquelas.' },
    { v: 24, en: 'Ye blind guides, which strain at a gnat, and swallow a camel.', pt: 'Guias cegos, que coais o mosquito e engulis o camelo!' },
    { v: 25, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye make clean the outside of the cup and of the platter, but within they are full of extortion and excess.', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque limpais o exterior do copo e do prato, mas por dentro estão cheios de rapina e intemperança.' },
    { v: 26, en: 'Thou blind Pharisee, cleanse first that which is within the cup and platter, that the outside of them may be clean also.', pt: 'Fariseu cego! Limpa primeiro o interior do copo e do prato, para que também o exterior fique limpo.' },
    { v: 27, en: 'Woe unto you, scribes and Pharisees, hypocrites! for ye are like unto whited sepulchres, which indeed appear beautiful outward, but are within full of dead men\'s bones, and of all uncleanness.', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque sois semelhantes aos sepulcros caiados, que por fora parecem belos, mas por dentro estão cheios de ossos de mortos e de toda a imundícia.' },
    { v: 28, en: 'Even so ye also outwardly appear righteous unto men, but within ye are full of hypocrisy and iniquity.', pt: 'Assim também vós pareceis justos aos homens por fora, mas por dentro estais cheios de hipocrisia e iniquidade.' },
    { v: 29, en: 'Woe unto you, scribes and Pharisees, hypocrites! because ye build the tombs of the prophets, and garnish the sepulchres of the righteous,', pt: 'Ai de vós, escribas e fariseus, hipócritas! Porque edificais os túmulos dos profetas e adornais os sepulcros dos justos,' },
    { v: 30, en: 'And say, If we had been in the days of our fathers, we would not have been partakers with them in the blood of the prophets.', pt: 'e dizeis: Se tivéssemos vivido nos dias dos nossos pais, não teríamos sido seus cúmplices no sangue dos profetas.' },
    { v: 31, en: 'Wherefore ye be witnesses unto yourselves, that ye are the children of them which killed the prophets.', pt: 'Assim, testificais contra vós mesmos que sois filhos dos que mataram os profetas.' },
    { v: 32, en: 'Fill ye up then the measure of your fathers.', pt: 'Enchei vós também a medida dos vossos pais.' },
    { v: 33, en: 'Ye serpents, ye generation of vipers, how can ye escape the damnation of hell?', pt: 'Serpentes, raça de víboras! Como escapareis da condenação do inferno?' },
    { v: 34, en: 'Wherefore, behold, I send unto you prophets, and wise men, and scribes: and some of them ye shall kill and crucify; and some of them shall ye scourge in your synagogues, and persecute them from city to city:', pt: 'Por isso, eis que eu vos envio profetas, sábios e escribas; e de alguns deles matareis e crucificareis, e de outros açoitareis nas vossas sinagogas e os perseguireis de cidade em cidade;' },
    { v: 35, en: 'That upon you may come all the righteous blood shed upon the earth, from the blood of righteous Abel unto the blood of Zacharias son of Barachias, whom ye slew between the temple and the altar.', pt: 'para que sobre vós recaia todo o sangue justo derramado sobre a terra, desde o sangue de Abel, o justo, até ao sangue de Zacarias, filho de Baraquias, que matastes entre o santuário e o altar.' },
    { v: 36, en: 'Verily I say unto you, All these things shall come upon this generation.', pt: 'Em verdade vos digo que todas estas coisas hão de vir sobre esta geração.' },
    { v: 37, en: 'O Jerusalem, Jerusalem, thou that killest the prophets, and stonest them which are sent unto thee, how often would I have gathered thy children together, even as a hen gathereth her chickens under her wings, and ye would not!', pt: 'Jerusalém, Jerusalém, que matas os profetas e apedrejas os que são enviados a ti! Quantas vezes quis eu reunir os teus filhos, como a galinha ajunta os seus pintinhos debaixo das asas, e vós não quisestes!' },
    { v: 38, en: 'Behold, your house is left unto you desolate.', pt: 'Eis que a vossa casa vos será deixada deserta.' },
    { v: 39, en: 'For I say unto you, Ye shall not see me henceforth, till ye shall say, Blessed is he that cometh in the name of the Lord.', pt: 'Porque vos digo que, desde agora, não me vereis mais, até que digais: Bendito o que vem em nome do Senhor.' },
  ],
  24: [
    { v: 1, en: 'And Jesus went out, and departed from the temple: and his disciples came to him for to shew him the buildings of the temple.', pt: 'E, saindo Jesus do templo, ia-se embora; e os seus discípulos chegaram-se a ele para lhe mostrar os edifícios do templo.' },
    { v: 2, en: 'And Jesus said unto them, See ye not all these things? verily I say unto you, There shall not be left here one stone upon another, that shall not be thrown down.', pt: 'E Jesus disse-lhes: Não vedes tudo isso? Em verdade vos digo que não ficará aqui pedra sobre pedra que não seja derrubada.' },
    { v: 3, en: 'And as he sat upon the mount of Olives, the disciples came unto him privately, saying, Tell us, when shall these things be? and what shall be the sign of thy coming, and of the end of the world?', pt: 'E, estando ele assentado no monte das Oliveiras, os discípulos aproximaram-se dele em particular, dizendo: Dize-nos quando serão estas coisas? e qual será o sinal da tua vinda e do fim do mundo?' },
    { v: 4, en: 'And Jesus answered and said unto them, Take heed that no man deceive you.', pt: 'E Jesus, respondendo, disse-lhes: Acautelai-vos, para que ninguém vos engane.' },
    { v: 5, en: 'For many shall come in my name, saying, I am Christ; and shall deceive many.', pt: 'Porque muitos virão em meu nome, dizendo: Eu sou o Cristo; e enganarão a muitos.' },
    { v: 6, en: 'And ye shall hear of wars and rumours of wars: see that ye be not troubled: for all these things must come to pass, but the end is not yet.', pt: 'E ouvireis guerras e rumores de guerras; vede que não vos perturbeis, porque é necessário que tudo isso aconteça; mas ainda não é o fim.' },
    { v: 7, en: 'For nation shall rise against nation, and kingdom against kingdom: and there shall be famines, and pestilences, and earthquakes, in divers places.', pt: 'Porque se levantará nação contra nação, e reino contra reino, e haverá fomes, e pestilências, e terremotos em vários lugares.' },
    { v: 8, en: 'All these are the beginning of sorrows.', pt: 'Mas tudo isso é o princípio das dores.' },
    { v: 9, en: 'Then shall they deliver you up to be afflicted, and shall kill you: and ye shall be hated of all nations for my name\'s sake.', pt: 'Então vos entregarão para serdes atormentados e vos matarão; e sereis odiados de todas as nações por causa do meu nome.' },
    { v: 10, en: 'And then shall many be offended, and shall betray one another, and shall hate one another.', pt: 'E muitos se escandalizarão, e trair-se-ão uns aos outros, e uns aos outros se odiarão.' },
    { v: 11, en: 'And many false prophets shall rise, and shall deceive many.', pt: 'E muitos falsos profetas se levantarão, e enganarão a muitos.' },
    { v: 12, en: 'And because iniquity shall abound, the love of many shall wax cold.', pt: 'E, por se multiplicar a iniquidade, o amor de muitos esfriará.' },
    { v: 13, en: 'But he that shall endure unto the end, the same shall be saved.', pt: 'Mas aquele que perseverar até ao fim, esse será salvo.' },
    { v: 14, en: 'And this gospel of the kingdom shall be preached in all the world for a witness unto all nations; and then shall the end come.', pt: 'E este evangelho do reino será pregado em todo o mundo, em testemunho a todas as nações, e então virá o fim.' },
    { v: 15, en: 'When ye therefore shall see the abomination of desolation, spoken of by Daniel the prophet, stand in the holy place, (whoso readeth, let him understand:)', pt: 'Quando, pois, virdes que a abominação da desolação, de que falou o profeta Daniel, está no lugar santo (quem lê, entenda),' },
    { v: 16, en: 'Then let them which be in Judaea flee into the mountains:', pt: 'então os que estiverem na Judeia, fujam para os montes;' },
    { v: 17, en: 'Let him which is on the housetop not come down to take any thing out of his house:', pt: 'o que estiver sobre o telhado não desça a buscar as coisas que estão na sua casa;' },
    { v: 18, en: 'Neither let him which is in the field return back to take his clothes.', pt: 'e o que estiver no campo não volte atrás buscar as suas vestes.' },
    { v: 19, en: 'And woe unto them that are with child, and to them that give suck in those days!', pt: 'Ai das que estiverem grávidas e das que amamentarem naqueles dias!' },
    { v: 20, en: 'But pray ye that your flight be not in the winter, neither on the sabbath day:', pt: 'Orai para que a vossa fuga não seja no inverno, nem no dia de sábado;' },
    { v: 21, en: 'For then shall be great tribulation, such as was not since the beginning of the world to this time, no, nor ever shall be.', pt: 'porque então haverá grande tribulação, como nunca houve desde o princípio do mundo até ao presente, nem jamais haverá.' },
    { v: 22, en: 'And except those days should be shortened, there should no flesh be saved: but for the elect\'s sake those days shall be shortened.', pt: 'E, se aqueles dias não fossem abreviados, nenhuma carne se salvaria; mas, por causa dos escolhidos, aqueles dias serão abreviados.' },
    { v: 23, en: 'Then if any man shall say unto you, Lo, here is Christ, or there; believe it not.', pt: 'Então, se alguém vos disser: Eis aqui o Cristo, ou ali, não creiais.' },
    { v: 24, en: 'For there shall arise false Christs, and false prophets, and shall shew great signs and wonders; insomuch that, if it were possible, they shall deceive the very elect.', pt: 'Porque surgirão falsos cristos e falsos profetas, e farão grandes sinais e prodígios, a ponto de enganar, se possível fosse, até os escolhidos.' },
    { v: 25, en: 'Behold, I have told you before.', pt: 'Eis que eu vo-lo tenho dito de antemão.' },
    { v: 26, en: 'Wherefore if they shall say unto you, Behold, he is in the desert; go not forth: behold, he is in the secret chambers; believe it not.', pt: 'Portanto, se vos disserem: Eis que está no deserto, não saiais; eis que está nas câmaras interiores, não creiais.' },
    { v: 27, en: 'For as the lightning cometh out of the east, and shineth even unto the west; so shall also the coming of the Son of man be.', pt: 'Porque, assim como o relâmpago sai do oriente e se mostra até ao ocidente, assim será também a vinda do Filho do Homem.' },
    { v: 28, en: 'For wheresoever the carcase is, there will the eagles be gathered together.', pt: 'Porque onde estiver o cadáver, aí se ajuntarão as águias.' },
    { v: 29, en: 'Immediately after the tribulation of those days shall the sun be darkened, and the moon shall not give her light, and the stars shall fall from heaven, and the powers of the heavens shall be shaken:', pt: 'E logo depois da tribulação daqueles dias, o sol escurecerá, e a lua não dará o seu resplendor, e as estrelas cairão do céu, e as potências dos céus serão abaladas.' },
    { v: 30, en: 'And then shall appear the sign of the Son of man in heaven: and then shall all the tribes of the earth mourn, and they shall see the Son of man coming in the clouds of heaven with power and great glory.', pt: 'E então aparecerá no céu o sinal do Filho do Homem; e todas as tribos da terra se lamentarão, e verão o Filho do Homem vindo sobre as nuvens do céu, com poder e grande glória.' },
    { v: 31, en: 'And he shall send his angels with a great sound of a trumpet, and they shall gather together his elect from the four winds, from one end of heaven to the other.', pt: 'E ele enviará os seus anjos com grande som de trombeta, e eles reunirão os seus escolhidos dos quatro ventos, de uma extremidade dos céus até à outra.' },
    { v: 32, en: 'Now learn a parable of the fig tree; When his branch is yet tender, and putteth forth leaves, ye know that summer is nigh:', pt: 'Aprendei, pois, esta parábola da figueira: Quando já os seus ramos se tornam tenros e brotam folhas, sabeis que o verão está próximo.' },
    { v: 33, en: 'So likewise ye, when ye shall see all these things, know that it is near, even at the doors.', pt: 'Assim também vós, quando virdes todas estas coisas, sabei que ele está próximo, às portas.' },
    { v: 34, en: 'Verily I say unto you, This generation shall not pass, till all these things be fulfilled.', pt: 'Em verdade vos digo que não passará esta geração sem que todas estas coisas aconteçam.' },
    { v: 35, en: 'Heaven and earth shall pass away, but my words shall not pass away.', pt: 'O céu e a terra passarão, mas as minhas palavras não passarão.' },
    { v: 36, en: 'But of that day and hour knoweth no man, no, not the angels of heaven, but my Father only.', pt: 'Mas a respeito daquele dia e hora ninguém sabe, nem os anjos dos céus, mas somente meu Pai.' },
    { v: 37, en: 'But as the days of Noe were, so shall also the coming of the Son of man be.', pt: 'Mas, assim como foram os dias de Noé, assim será a vinda do Filho do Homem.' },
    { v: 38, en: 'For as in the days that were before the flood they were eating and drinking, marrying and giving in marriage, until the day that Noe entered into the ark,', pt: 'Porque, assim como nos dias antes do dilúvio, estavam comendo e bebendo, casando e dando em casamento, até ao dia em que Noé entrou na arca,' },
    { v: 39, en: 'And knew not until the flood came, and took them all away; so shall also the coming of the Son of man be.', pt: 'e não o perceberam, até que veio o dilúvio e os levou a todos; assim será também a vinda do Filho do Homem.' },
    { v: 40, en: 'Then shall two be in the field; the one shall be taken, and the other left.', pt: 'Então, dois estarão no campo; um será tomado, e o outro deixado.' },
    { v: 41, en: 'Two women shall be grinding at the mill; the one shall be taken, and the other left.', pt: 'Duas mulheres estarão moendo no moinho; uma será tomada, e a outra deixada.' },
    { v: 42, en: 'Watch therefore: for ye know not what hour your Lord doth come.', pt: 'Vigiai, pois, porque não sabeis a que hora virá o vosso Senhor.' },
    { v: 43, en: 'But know this, that if the goodman of the house had known in what watch the thief would come, he would have watched, and would not have suffered his house to be broken up.', pt: 'Mas sabei isto: que, se o pai de família soubesse a que horas o ladrão viria, velaria e não deixaria minar a sua casa.' },
    { v: 44, en: 'Therefore be ye also ready: for in such an hour as ye think not the Son of man cometh.', pt: 'Por isso, estai vós também prontos; porque, à hora em que não pensais, o Filho do Homem virá.' },
    { v: 45, en: 'Who then is a faithful and wise servant, whom his lord hath made ruler over his household, to give them meat in due season?', pt: 'Quem é, pois, o servo fiel e prudente, que o seu senhor constituiu sobre os seus domésticos para lhes dar o sustento a seu tempo?' },
    { v: 46, en: 'Blessed is that servant, whom his lord when he cometh shall find so doing.', pt: 'Bem-aventurado aquele servo que o seu senhor, quando vier, achar assim fazendo.' },
    { v: 47, en: 'Verily I say unto you, That he shall make him ruler over all his goods.', pt: 'Em verdade vos digo que o porá sobre todos os seus bens.' },
    { v: 48, en: 'But and if that evil servant shall say in his heart, My lord delayeth his coming;', pt: 'Mas, se aquele servo mau disser no seu coração: O meu senhor tarda em vir,' },
    { v: 49, en: 'And shall begin to smite his fellowservants, and to eat and drink with the drunken;', pt: 'e começar a espancar os seus conservos e a comer e beber com os ébrios;' },
    { v: 50, en: 'The lord of that servant shall come in a day when he looketh not for him, and in an hour that he is not aware of,', pt: 'virá o senhor daquele servo num dia em que ele não espera e numa hora que não sabe;' },
    { v: 51, en: 'And shall cut him asunder, and appoint him his portion with the hypocrites: there shall be weeping and gnashing of teeth.', pt: 'e castigá-lo-á severamente e lhe dará a sua parte com os hipócritas; ali haverá choro e ranger de dentes.' },
  ],
  25: [
    { v: 1, en: 'Then shall the kingdom of heaven be likened unto ten virgins, which took their lamps, and went forth to meet the bridegroom.', pt: 'Então o reino dos céus será semelhante a dez virgens que, tomando as suas lâmpadas, saíram ao encontro do noivo.' },
    { v: 2, en: 'And five of them were wise, and five were foolish.', pt: 'E cinco delas eram prudentes e cinco eram néscias.' },
    { v: 3, en: 'They that were foolish took their lamps, and took no oil with them:', pt: 'As néscias, tomando as suas lâmpadas, não levaram consigo azeite;' },
    { v: 4, en: 'But the wise took oil in their vessels with their lamps.', pt: 'mas as prudentes levaram azeite nos seus vasos juntamente com as suas lâmpadas.' },
    { v: 5, en: 'While the bridegroom tarried, they all slumbered and slept.', pt: 'E, tardando o noivo, tosquenejaram todas e adormeceram.' },
    { v: 6, en: 'And at midnight there was a cry made, Behold, the bridegroom cometh; go ye out to meet him.', pt: 'E à meia-noite ouviu-se um clamor: Eis que vem o noivo; saí ao seu encontro.' },
    { v: 7, en: 'Then all those virgins arose, and trimmed their lamps.', pt: 'Então todas aquelas virgens se levantaram e prepararam as suas lâmpadas.' },
    { v: 8, en: 'And the foolish said unto the wise, Give us of your oil; for our lamps are gone out.', pt: 'E as néscias disseram às prudentes: Dai-nos do vosso azeite, porque as nossas lâmpadas se apagam.' },
    { v: 9, en: 'But the wise answered, saying, Not so; lest there be not enough for us and you: but go ye rather to them that sell, and buy for yourselves.', pt: 'Mas as prudentes responderam: Não, para que não nos falte a nós e a vós; ide antes aos que vendem e comprai para vós.' },
    { v: 10, en: 'And while they went to buy, the bridegroom came; and they that were ready went in with him to the marriage: and the door was shut.', pt: 'E, indo elas comprar, chegou o noivo; e as que estavam prontas entraram com ele para as bodas, e a porta se fechou.' },
    { v: 11, en: 'Afterward came also the other virgins, saying, Lord, Lord, open to us.', pt: 'Depois chegaram também as outras virgens, dizendo: Senhor, Senhor, abre-nos!' },
    { v: 12, en: 'But he answered and said, Verily I say unto you, I know you not.', pt: 'Mas ele, respondendo, disse: Em verdade vos digo que vos não conheço.' },
    { v: 13, en: 'Watch therefore, for ye know neither the day nor the hour wherein the Son of man cometh.', pt: 'Vigiai, pois, porque não sabeis o dia nem a hora em que o Filho do Homem virá.' },
    { v: 14, en: 'For the kingdom of heaven is as a man travelling into a far country, who called his own servants, and delivered unto them his goods.', pt: 'Porque o reino dos céus é como um homem que, partindo em viagem, chamou os seus servos e entregou-lhes os seus bens.' },
    { v: 15, en: 'And unto one he gave five talents, to another two, and to another one; to every man according to his several ability; and straightway took his journey.', pt: 'E a um deu cinco talentos, a outro dois, e a outro um, a cada um segundo a sua própria capacidade; e logo partiu.' },
    { v: 16, en: 'Then he that had received the five talents went and traded with the same, and made them other five talents.', pt: 'E aquele que recebera cinco talentos foi negociar com eles e ganhou outros cinco talentos.' },
    { v: 17, en: 'And likewise he that had received two, he also gained other two.', pt: 'Da mesma forma, o que recebera dois ganhou outros dois.' },
    { v: 18, en: 'But he that had received one went and digged in the earth, and hid his lord\'s money.', pt: 'Mas o que recebera um só foi cavou a terra e escondeu o dinheiro do seu senhor.' },
    { v: 19, en: 'After a long time the lord of those servants cometh, and reckoneth with them.', pt: 'E, depois de muito tempo, voltou o senhor daqueles servos e ajustou contas com eles.' },
    { v: 20, en: 'And so he that had received five talents came and brought other five talents, saying, Lord, thou deliveredst unto me five talents: behold, I have gained beside them five talents more.', pt: 'E, chegando o que recebera cinco talentos, trouxe outros cinco talentos, dizendo: Senhor, entregaste-me cinco talentos; eis que ganhei mais cinco talentos.' },
    { v: 21, en: 'His lord said unto him, Well done, thou good and faithful servant: thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.', pt: 'E o seu senhor disse-lhe: Bem está, servo bom e fiel; sobre o pouco foste fiel, sobre muito te constituirei; entra no gozo do teu senhor.' },
    { v: 22, en: 'He also that had received two talents came and said, Lord, thou deliveredst unto me two talents: behold, I have gained two other talents beside them.', pt: 'Chegou também o que recebera dois talentos, e disse: Senhor, entregaste-me dois talentos; eis que ganhei mais dois talentos.' },
    { v: 23, en: 'His lord said unto him, Well done, good and faithful servant; thou hast been faithful over a few things, I will make thee ruler over many things: enter thou into the joy of thy lord.', pt: 'O seu senhor disse-lhe: Bem está, servo bom e fiel; sobre o pouco foste fiel, sobre muito te constituirei; entra no gozo do teu senhor.' },
    { v: 24, en: 'Then he which had received the one talent came and said, Lord, I knew thee that thou art an hard man, reaping where thou hast not sown, and gathering where thou hast not strawed:', pt: 'E, chegando também o que recebera um talento, disse: Senhor, conhecia-te, que és homem severo, que ceifas onde não semeaste e ajuntas onde não espalhaste;' },
    { v: 25, en: 'And I was afraid, and went and hid thy talent in the earth: lo, there thou hast that is thine.', pt: 'e, com medo, fui esconder o teu talento na terra; aqui tens o que é teu.' },
    { v: 26, en: 'His lord answered and said unto him, Thou wicked and slothful servant, thou knewest that I reap where I sowed not, and gather where I have not strawed:', pt: 'E o seu senhor respondeu: Servo mau e preguiçoso, sabias que ceifo onde não semeei e ajunto onde não espalhei?' },
    { v: 27, en: 'Thou oughtest therefore to have put my money to the exchangers, and then at my coming I should have received mine own with usury.', pt: 'Então devias ter dado o meu dinheiro aos banqueiros, e eu, chegando, receberia o que é meu com juros.' },
    { v: 28, en: 'Take therefore the talent from him, and give it unto him which hath ten talents.', pt: 'Tirai-lhe, pois, o talento e dai-o ao que tem dez talentos.' },
    { v: 29, en: 'For unto every one that hath shall be given, and he shall have abundance: but from him that hath not shall be taken away even that which he hath.', pt: 'Porque a qualquer que tem será dado, e terá em abundância; mas ao que não tem, até o que tem ser-lhe-á tirado.' },
    { v: 30, en: 'And cast ye the unprofitable servant into outer darkness: there shall be weeping and gnashing of teeth.', pt: 'E ao servo inútil lançai-o nas trevas exteriores; ali haverá choro e ranger de dentes.' },
    { v: 31, en: 'When the Son of man shall come in his glory, and all the holy angels with him, then shall he sit upon the throne of his glory:', pt: 'Quando o Filho do Homem vier na sua glória, e todos os santos anjos com ele, então se assentará no trono da sua glória.' },
    { v: 32, en: 'And before him shall be gathered all nations: and he shall separate them one from another, as a shepherd divideth his sheep from the goats:', pt: 'E serão reunidas diante dele todas as nações; e ele separará uns dos outros, como o pastor separa as ovelhas dos cabritos.' },
    { v: 33, en: 'And he shall set the sheep on his right hand, but the goats on the left.', pt: 'E porá as ovelhas à sua direita, mas os cabritos à esquerda.' },
    { v: 34, en: 'Then shall the King say unto them on his right hand, Come, ye blessed of my Father, inherit the kingdom prepared for you from the foundation of the world:', pt: 'Então o Rei dirá aos que estiverem à sua direita: Vinde, benditos de meu Pai, possuí por herança o reino que vos está preparado desde a fundação do mundo.' },
    { v: 35, en: 'For I was an hungred, and ye gave me meat: I was thirsty, and ye gave me drink: I was a stranger, and ye took me in:', pt: 'Porque tive fome, e me destes de comer; tive sede, e me destes de beber; era estrangeiro, e me hospedastes;' },
    { v: 36, en: 'Naked, and ye clothed me: I was sick, and ye visited me: I was in prison, and ye came unto me.', pt: 'estava nu, e me vestistes; estive doente, e me visitastes; estava preso, e fostes ver-me.' },
    { v: 37, en: 'Then shall the righteous answer him, saying, Lord, when saw we thee an hungred, and fed thee? or thirsty, and gave thee drink?', pt: 'Então os justos lhe responderão: Senhor, quando te vimos com fome e te demos de comer? Ou com sede e te demos de beber?' },
    { v: 38, en: 'When saw we thee a stranger, and took thee in? or naked, and clothed thee?', pt: 'E quando te vimos estrangeiro e te hospedarmos? Ou nu e te vestimos?' },
    { v: 39, en: 'Or when saw we thee sick, or in prison, and came unto thee?', pt: 'E quando te vimos doente, ou preso, e fomos ver-te?' },
    { v: 40, en: 'And the King shall answer and say unto them, Verily I say unto you, Inasmuch as ye have done it unto one of the least of these my brethren, ye have done it unto me.', pt: 'E o Rei, respondendo, lhes dirá: Em verdade vos digo que, sempre que o fizestes a um destes meus pequeninos irmãos, a mim o fizestes.' },
    { v: 41, en: 'Then shall he say also unto them on the left hand, Depart from me, ye cursed, into everlasting fire, prepared for the devil and his angels:', pt: 'Então dirá também aos da esquerda: Apartai-vos de mim, malditos, para o fogo eterno, preparado para o diabo e os seus anjos.' },
    { v: 42, en: 'For I was an hungred, and ye gave me no meat: I was thirsty, and ye gave me no drink:', pt: 'Porque tive fome, e não me destes de comer; tive sede, e não me destes de beber;' },
    { v: 43, en: 'I was a stranger, and ye took me not in: naked, and ye clothed me not: sick, and in prison, and ye visited me not.', pt: 'era estrangeiro, e não me hospedastes; estava nu, e não me vestistes; doente e preso, e não me visitastes.' },
    { v: 44, en: 'Then shall they also answer him, saying, Lord, when saw we thee an hungred, or athirst, or a stranger, or naked, or sick, or in prison, and did not minister unto thee?', pt: 'Então lhe responderão também eles: Senhor, quando te vimos com fome, ou com sede, ou estrangeiro, ou nu, ou doente, ou preso, e não te servimos?' },
    { v: 45, en: 'Then shall he answer them, saying, Verily I say unto you, Inasmuch as ye did it not to one of the least of these, ye did it not to me.', pt: 'Então ele lhes responderá: Em verdade vos digo que, sempre que o não fizestes a um destes pequeninos, também a mim não o fizestes.' },
    { v: 46, en: 'And these shall go away into everlasting punishment: but the righteous into life eternal.', pt: 'E irão estes para o tormento eterno, mas os justos para a vida eterna.' },
  ],
  26: [
    { v: 1, en: 'And it came to pass, when Jesus had finished all these sayings, he said unto his disciples,', pt: 'E aconteceu que, quando Jesus acabou todos estes discursos, disse aos seus discípulos:' },
    { v: 2, en: 'Ye know that after two days is the feast of the passover, and the Son of man is betrayed to be crucified.', pt: 'Sabeis que daqui a dois dias será a Páscoa, e o Filho do Homem será entregue para ser crucificado.' },
    { v: 3, en: 'Then assembled together the chief priests, and the scribes, and the elders of the people, unto the palace of the high priest, who was called Caiaphas,', pt: 'Então os principais sacerdotes, os escribas e os anciãos do povo reuniram-se no átrio do sumo sacerdote, que se chamava Caifás,' },
    { v: 4, en: 'And consulted that they might take Jesus by subtilty, and kill him.', pt: 'e deliberaram prender Jesus por astúcia e matá-lo.' },
    { v: 5, en: 'But they said, Not on the feast day, lest there be an uproar among the people.', pt: 'Mas diziam: Não durante a festa, para não haver tumulto entre o povo.' },
    { v: 6, en: 'Now when Jesus was in Bethany, in the house of Simon the leper,', pt: 'E estando Jesus em Betânia, em casa de Simão o leproso,' },
    { v: 7, en: 'There came unto him a woman having an alabaster box of very precious ointment, and poured it on his head, as he sat at meat.', pt: 'chegou a ele uma mulher com um vaso de alabastro de ungüento muito precioso, e o derramou sobre a cabeça dele, enquanto ele estava à mesa.' },
    { v: 8, en: 'But when his disciples saw it, they had indignation, saying, To what purpose is this waste?', pt: 'E os discípulos, vendo isso, indignaram-se, dizendo: Para que este desperdício?' },
    { v: 9, en: 'For this ointment might have been sold for much, and given to the poor.', pt: 'Porque este ungüento podia ser vendido por muito e dado aos pobres.' },
    { v: 10, en: 'When Jesus understood it, he said unto them, Why trouble ye the woman? for she hath wrought a good work upon me.', pt: 'E Jesus, percebendo isso, disse-lhes: Por que molestais a mulher? Ela fez uma boa obra para comigo.' },
    { v: 11, en: 'For ye have the poor always with you; but me ye have not always.', pt: 'Porque os pobres sempre os tendes convosco, mas a mim não me tereis sempre.' },
    { v: 12, en: 'For in that she hath poured this ointment on my body, she did it for my burial.', pt: 'Porque, derramando ela este ungüento sobre o meu corpo, fê-lo para o meu sepultamento.' },
    { v: 13, en: 'Verily I say unto you, Wheresoever this gospel shall be preached in the whole world, there shall also this, that this woman hath done, be told for a memorial of her.', pt: 'Em verdade vos digo que, onde quer que este evangelho for pregado em todo o mundo, será também contado, em memória dela, o que ela fez.' },
    { v: 14, en: 'Then one of the twelve, called Judas Iscariot, went unto the chief priests,', pt: 'Então um dos doze, chamado Judas Iscariotes, foi ter com os principais sacerdotes' },
    { v: 15, en: 'And said unto them, What will ye give me, and I will deliver him unto you? And they covenanted with him for thirty pieces of silver.', pt: 'e disse: Que me quereis dar, e eu vo-lo entregarei? E eles lhe pesaram trinta moedas de prata.' },
    { v: 16, en: 'And from that time he sought opportunity to betray him.', pt: 'E desde então procurava oportunidade para o entregar.' },
    { v: 17, en: 'Now the first day of the feast of unleavened bread the disciples came to Jesus, saying unto him, Where wilt thou that we prepare for thee to eat the passover?', pt: 'E no primeiro dia dos pães asmos, os discípulos chegaram-se a Jesus, dizendo: Onde queres que te preparemos a Páscoa para comer?' },
    { v: 18, en: 'And he said, Go into the city to such a man, and say unto him, The Master saith, My time is at hand; I will keep the passover at thy house with my disciples.', pt: 'E ele disse: Ide à cidade, a certo homem, e dizei-lhe: O Mestre diz: O meu tempo está próximo; farei a Páscoa em tua casa com os meus discípulos.' },
    { v: 19, en: 'And the disciples did as Jesus had appointed them; and they made ready the passover.', pt: 'E os discípulos fizeram como Jesus lhes ordenara e prepararam a Páscoa.' },
    { v: 20, en: 'Now when the even was come, he sat down with the twelve.', pt: 'E, chegada a tarde, assentou-se à mesa com os doze.' },
    { v: 21, en: 'And as they did eat, he said, Verily I say unto you, that one of you shall betray me.', pt: 'E, enquanto comiam, disse: Em verdade vos digo que um de vós me trairá.' },
    { v: 22, en: 'And they were exceeding sorrowful, and began every one of them to say unto him, Lord, is it I?', pt: 'E eles, entristecendo-se muito, começaram cada um a dizer-lhe: Serei eu, Senhor?' },
    { v: 23, en: 'And he answered and said, He that dippeth his hand with me in the dish, the same shall betray me.', pt: 'E ele, respondendo, disse: O que mete a mão comigo no prato, esse me trairá.' },
    { v: 24, en: 'The Son of man goeth as it is written of him: but woe unto that man by whom the Son of man is betrayed! it had been good for that man if he had not been born.', pt: 'O Filho do Homem vai, como está escrito dele; mas ai daquele homem por quem o Filho do Homem é traído! Melhor lhe fora não haver nascido.' },
    { v: 25, en: 'Then Judas, which betrayed him, answered and said, Master, is it I? He said unto him, Thou hast said.', pt: 'E Judas, que o traiu, respondendo, disse: Serei eu, Mestre? Disse-lhe ele: Tu o disseste.' },
    { v: 26, en: 'And as they were eating, Jesus took bread, and blessed it, and brake it, and gave it to the disciples, and said, Take, eat; this is my body.', pt: 'E, enquanto comiam, tomou Jesus o pão e, abençoando-o, partiu-o e o deu aos discípulos, dizendo: Tomai, comei; isto é o meu corpo.' },
    { v: 27, en: 'And he took the cup, and gave thanks, and gave it to them, saying, Drink ye all of it;', pt: 'E, tomando o cálice e dando graças, deu-lho, dizendo: Bebei dele todos;' },
    { v: 28, en: 'For this is my blood of the new testament, which is shed for many for the remission of sins.', pt: 'porque isto é o meu sangue, o sangue do novo testamento, que é derramado por muitos para remissão dos pecados.' },
    { v: 29, en: 'But I say unto you, I will not drink henceforth of this fruit of the vine, until that day when I drink it new with you in my Father\'s kingdom.', pt: 'E digo-vos que, desde agora, não beberei deste fruto da videira até àquele dia em que o beba novo convosco no reino de meu Pai.' },
    { v: 30, en: 'And when they had sung an hymn, they went out into the mount of Olives.', pt: 'E, tendo cantado um hino, saíram para o monte das Oliveiras.' },
    { v: 31, en: 'Then saith Jesus unto them, All ye shall be offended because of me this night: for it is written, I will smite the shepherd, and the sheep of the flock shall be scattered abroad.', pt: 'Então Jesus lhes disse: Todos vós vos escandalizareis em mim esta noite; porque está escrito: Ferirei o pastor, e as ovelhas do rebanho serão dispersas.' },
    { v: 32, en: 'But after I am risen again, I will go before you into Galilee.', pt: 'Mas, depois que eu ressuscitar, irei adiante de vós para a Galileia.' },
    { v: 33, en: 'Peter answered and said unto him, Though all men shall be offended because of thee, yet will I never be offended.', pt: 'E Pedro, respondendo, disse-lhe: Ainda que todos se escandalizem em ti, eu nunca me escandalizarei.' },
    { v: 34, en: 'Jesus said unto him, Verily I say unto thee, That this night, before the cock crow, thou shalt deny me thrice.', pt: 'Jesus disse-lhe: Em verdade te digo que esta noite, antes que o galo cante, me negarás três vezes.' },
    { v: 35, en: 'Peter said unto him, Though I should die with thee, yet will I not deny thee. Likewise also said all the disciples.', pt: 'Pedro disse-lhe: Ainda que me seja necessário morrer contigo, não te negarei. E todos os discípulos disseram o mesmo.' },
    { v: 36, en: 'Then cometh Jesus with them unto a place called Gethsemane, and saith unto the disciples, Sit ye here, while I go and pray yonder.', pt: 'Então chegou Jesus com eles a um lugar chamado Getsêmani e disse aos discípulos: Assentai-vos aqui enquanto eu vou além a orar.' },
    { v: 37, en: 'And he took with him Peter and the two sons of Zebedee, and began to be sorrowful and very heavy.', pt: 'E, levando consigo a Pedro e os dois filhos de Zebedeu, começou a entristecer-se e a angustiar-se.' },
    { v: 38, en: 'Then saith he unto them, My soul is exceeding sorrowful, even unto death: tarry ye here, and watch with me.', pt: 'Então lhes disse: A minha alma está profundamente triste, até à morte; ficai aqui e velai comigo.' },
    { v: 39, en: 'And he went a little further, and fell on his face, and prayed, saying, O my Father, if it be possible, let this cup pass from me: nevertheless not as I will, but as thou wilt.', pt: 'E, indo um pouco mais além, prostrou-se com o rosto em terra, orando e dizendo: Meu Pai, se é possível, passa de mim este cálice; todavia, não seja como eu quero, mas como tu queres.' },
    { v: 40, en: 'And he cometh unto the disciples, and findeth them asleep, and saith unto Peter, What, could ye not watch with me one hour?', pt: 'E, voltando para os discípulos, achou-os adormecidos; e disse a Pedro: Então nem uma hora pudestes vós velar comigo?' },
    { v: 41, en: 'Watch and pray, that ye enter not into temptation: the spirit indeed is willing, but the flesh is weak.', pt: 'Velai e orai, para que não entreis em tentação; o espírito, na verdade, está pronto, mas a carne é fraca.' },
    { v: 42, en: 'He went away again the second time, and prayed, saying, O my Father, if this cup may not pass away from me, except I drink it, thy will be done.', pt: 'Tornou a afastar-se pela segunda vez e orou, dizendo: Meu Pai, se este cálice não pode passar sem que eu o beba, que se faça a tua vontade.' },
    { v: 43, en: 'And he came and found them asleep again: for their eyes were heavy.', pt: 'E, tornando, achou-os novamente adormecidos, porque os seus olhos estavam pesados.' },
    { v: 44, en: 'And he left them, and went away again, and prayed the third time, saying the same words.', pt: 'E, deixando-os, foi orar de novo pela terceira vez, dizendo as mesmas palavras.' },
    { v: 45, en: 'Then cometh he to his disciples, and saith unto them, Sleep on now, and take your rest: behold, the hour is at hand, and the Son of man is betrayed into the hands of sinners.', pt: 'Então voltou para os discípulos e disse-lhes: Dormi agora e repousai; eis que é chegada a hora, e o Filho do Homem é entregue nas mãos dos pecadores.' },
    { v: 46, en: 'Rise, let us be going: behold, he is at hand that doth betray me.', pt: 'Levantai-vos, vamos; eis que está próximo o que me trai.' },
    { v: 47, en: 'And while he yet spake, lo, Judas, one of the twelve, came, and with him a great multitude with swords and staves, from the chief priests and elders of the people.', pt: 'E, ainda ele falando, chegou Judas, um dos doze, e com ele uma grande multidão com espadas e varapaus, da parte dos principais sacerdotes e dos anciãos do povo.' },
    { v: 48, en: 'Now he that betrayed him gave them a sign, saying, Whomsoever I shall kiss, that same is he: hold him fast.', pt: 'E o que o traiu deu-lhes um sinal, dizendo: Aquele a quem eu der um beijo, é ele mesmo; prendei-o.' },
    { v: 49, en: 'And forthwith he came to Jesus, and said, Hail, master; and kissed him.', pt: 'E, aproximando-se logo de Jesus, disse: Salve, Mestre! E o beijou.' },
    { v: 50, en: 'And Jesus said unto him, Friend, wherefore art thou come? Then came they, and laid hands on Jesus, and took him.', pt: 'E Jesus disse-lhe: Amigo, a que vieste? Então se aproximaram, lançaram as mãos sobre Jesus e o prenderam.' },
    { v: 51, en: 'And, behold, one of them which were with Jesus stretched out his hand, and drew his sword, and struck a servant of the high priest\'s, and smote off his ear.', pt: 'E eis que um dos que estavam com Jesus, estendendo a mão, sacou da espada e, ferindo um servo do sumo sacerdote, cortou-lhe uma orelha.' },
    { v: 52, en: 'Then said Jesus unto him, Put up again thy sword into his place: for all they that take the sword shall perish with the sword.', pt: 'Então Jesus disse-lhe: Mete a tua espada no seu lugar; porque todos os que lançam mão da espada à espada morrerão.' },
    { v: 53, en: 'Thinkest thou that I cannot now pray to my Father, and he shall presently give me more than twelve legions of angels?', pt: 'Ou pensas tu que eu não poderia agora orar a meu Pai, e ele me enviaria já mais de doze legiões de anjos?' },
    { v: 54, en: 'But how then shall the scriptures be fulfilled, that thus it must be?', pt: 'Como, pois, se cumprirão as Escrituras que dizem que assim deve acontecer?' },
    { v: 55, en: 'In that same hour said Jesus to the multitudes, Are ye come out as against a thief with swords and staves for to take me? I sat daily with you teaching in the temple, and ye laid no hold on me.', pt: 'Naquela mesma hora, disse Jesus às multidões: Saístes, como para um ladrão, com espadas e varapaus, para me prender? Todos os dias me assentava no templo ensinando, e não me prendestes.' },
    { v: 56, en: 'But all this was done, that the scriptures of the prophets might be fulfilled. Then all the disciples forsook him, and fled.', pt: 'Mas tudo isso aconteceu para que se cumprissem as Escrituras dos profetas. Então todos os discípulos o abandonaram e fugiram.' },
    { v: 57, en: 'And they that had laid hold on Jesus led him away to Caiaphas the high priest, where the scribes and the elders were assembled.', pt: 'E os que prenderam Jesus o levaram a Caifás, o sumo sacerdote, onde os escribas e os anciãos estavam reunidos.' },
    { v: 58, en: 'But Peter followed him afar off unto the high priest\'s palace, and went in, and sat with the servants, to see the end.', pt: 'E Pedro o seguia de longe até ao átrio do sumo sacerdote; e, entrando, assentou-se com os servos para ver o fim.' },
    { v: 59, en: 'Now the chief priests, and elders, and all the council, sought false witness against Jesus, to put him to death;', pt: 'E os principais sacerdotes e os anciãos e todo o conselho procuravam falso testemunho contra Jesus, para o matar;' },
    { v: 60, en: 'But found none: yea, though many false witnesses came, yet found they none. At the last came two false witnesses,', pt: 'mas não acharam, ainda que muitas falsas testemunhas se apresentassem. Por fim, porém, vieram duas falsas testemunhas,' },
    { v: 61, en: 'And said, This fellow said, I am able to destroy the temple of God, and to build it in three days.', pt: 'que disseram: Este disse: Posso destruir o templo de Deus e reedificá-lo em três dias.' },
    { v: 62, en: 'And the high priest arose, and said unto him, Answerest thou nothing? what is it which these witness against thee?', pt: 'E o sumo sacerdote, levantando-se, disse-lhe: Nada respondes? Que testemunham estes contra ti?' },
    { v: 63, en: 'But Jesus held his peace. And the high priest answered and said unto him, I adjure thee by the living God, that thou tell us whether thou be the Christ, the Son of God.', pt: 'Mas Jesus calava-se. E o sumo sacerdote, respondendo, disse-lhe: Conjuro-te pelo Deus vivo, que nos digas se tu és o Cristo, o Filho de Deus.' },
    { v: 64, en: 'Jesus saith unto him, Thou hast said: nevertheless I say unto you, Hereafter shall ye see the Son of man sitting on the right hand of power, and coming in the clouds of heaven.', pt: 'Jesus disse-lhe: Tu o disseste; mas digo-vos que, doravante, vereis o Filho do Homem assentado à direita do Todo-Poderoso e vindo sobre as nuvens do céu.' },
    { v: 65, en: 'Then the high priest rent his clothes, saying, He hath spoken blasphemy; what further need have we of witnesses? behold, now ye have heard his blasphemy.', pt: 'Então o sumo sacerdote rasgou as suas vestes, dizendo: Blasfemou! Que mais necessidade temos de testemunhas? Eis que agora mesmo ouvistes a sua blasfêmia.' },
    { v: 66, en: 'What think ye? They answered and said, He is guilty of death.', pt: 'Que vos parece? Eles responderam: É réu de morte.' },
    { v: 67, en: 'Then did they spit in his face, and buffeted him; and others smote him with the palms of their hands,', pt: 'Então lhe cuspiam no rosto e o esbofeteavam; e outros o batiam com varas,' },
    { v: 68, en: 'Saying, Prophesy unto us, thou Christ, Who is he that smote thee?', pt: 'dizendo: Profetiza-nos, Cristo, quem é o que te bateu?' },
    { v: 69, en: 'Now Peter sat without in the palace: and a damsel came unto him, saying, Thou also wast with Jesus of Galilee.', pt: 'E Pedro estava assentado fora no átrio; e aproximou-se dele uma criada, dizendo: Tu também estavas com Jesus da Galileia.' },
    { v: 70, en: 'But he denied before them all, saying, I know not what thou sayest.', pt: 'Mas ele negou perante todos, dizendo: Não sei o que dizes.' },
    { v: 71, en: 'And when he was gone out into the porch, another maid saw him, and said unto them that were there, This fellow was also with Jesus of Nazareth.', pt: 'E, saindo ele para a entrada, viu-o outra criada e disse aos que estavam ali: Este também estava com Jesus de Nazaré.' },
    { v: 72, en: 'And again he denied with an oath, I do not know the man.', pt: 'E ele negou outra vez com juramento: Não conheço esse homem.' },
    { v: 73, en: 'And after a while came unto him they that stood by, and said to Peter, Surely thou also art one of them; for thy speech bewrayeth thee.', pt: 'E, depois de um pouco, aproximaram-se os que estavam ali e disseram a Pedro: Verdadeiramente tu também és um deles, porque o teu modo de falar te denuncia.' },
    { v: 74, en: 'Then began he to curse and to swear, saying, I know not the man. And immediately the cock crew.', pt: 'Então começou ele a praguejar e a jurar: Não conheço esse homem. E logo o galo cantou.' },
    { v: 75, en: 'And Peter remembered the word of Jesus, which said unto him, Before the cock crow, thou shalt deny me thrice. And he went out, and wept bitterly.', pt: 'E Pedro se lembrou das palavras de Jesus, que dissera: Antes que o galo cante, me negarás três vezes. E, saindo dali, chorou amargamente.' },
  ],
  27: [
    { v: 1, en: 'When the morning was come, all the chief priests and elders of the people took counsel against Jesus to put him to death:', pt: 'E, chegada a manhã, todos os principais sacerdotes e os anciãos do povo tomaram conselho contra Jesus para o matar.' },
    { v: 2, en: 'And when they had bound him, they led him away, and delivered him to Pontius Pilate the governor.', pt: 'E, tendo-o amarrado, o levaram e o entregaram a Pôncio Pilatos, o governador.' },
    { v: 3, en: 'Then Judas, which had betrayed him, when he saw that he was condemned, repented himself, and brought again the thirty pieces of silver to the chief priests and elders,', pt: 'Então Judas, o que o traiu, vendo que Jesus fora condenado, arrependido, restituiu as trinta moedas de prata aos principais sacerdotes e aos anciãos,' },
    { v: 4, en: 'Saying, I have sinned in that I have betrayed the innocent blood. And they said, What is that to us? see thou to that.', pt: 'dizendo: Pequei, traindo sangue inocente. Mas eles disseram: Que nos importa? Vê lá tu.' },
    { v: 5, en: 'And he cast down the pieces of silver in the temple, and departed, and went and hanged himself.', pt: 'E ele, lançando as moedas de prata no templo, retirou-se e foi enforcar-se.' },
    { v: 6, en: 'And the chief priests took the silver pieces, and said, It is not lawful for to put them into the treasury, because it is the price of blood.', pt: 'E os principais sacerdotes, tomando as moedas de prata, disseram: Não é lícito pô-las no cofre do tesouro, pois é preço de sangue.' },
    { v: 7, en: 'And they took counsel, and bought with them the potter\'s field, to bury strangers in.', pt: 'E, deliberando, compraram com elas o campo do oleiro, para sepultura de estrangeiros.' },
    { v: 8, en: 'Wherefore that field was called, The field of blood, unto this day.', pt: 'Por isso aquele campo foi chamado Campo do Sangue até ao dia de hoje.' },
    { v: 9, en: 'Then was fulfilled that which was spoken by Jeremy the prophet, saying, And they took the thirty pieces of silver, the price of him that was valued, whom they of the children of Israel did value;', pt: 'Então se cumpriu o que foi dito pelo profeta Jeremias: E tomaram as trinta moedas de prata, o preço do avaliado, que foi avaliado pelos filhos de Israel;' },
    { v: 10, en: 'And gave them for the potter\'s field, as the Lord appointed me.', pt: 'e as deram pelo campo do oleiro, como o Senhor me ordenou.' },
    { v: 11, en: 'And Jesus stood before the governor: and the governor asked him, saying, Art thou the King of the Jews? And Jesus said unto him, Thou sayest.', pt: 'E Jesus se apresentou perante o governador; e o governador lhe perguntou: És tu o Rei dos judeus? E Jesus disse-lhe: Tu o dizes.' },
    { v: 12, en: 'And when he was accused of the chief priests and elders, he answered nothing.', pt: 'E, sendo acusado pelos principais sacerdotes e pelos anciãos, nada respondeu.' },
    { v: 13, en: 'Then said Pilate unto him, Hearest thou not how many things they witness against thee?', pt: 'Então Pilatos lhe disse: Não ouves quantas coisas testificam contra ti?' },
    { v: 14, en: 'And he answered him to never a word; insomuch that the governor marvelled greatly.', pt: 'Mas ele não lhe respondeu nem uma palavra, de modo que o governador se admirou muito.' },
    { v: 15, en: 'Now at that feast the governor was wont to release unto the people a prisoner, whom they would.', pt: 'E por ocasião da festa o governador costumava soltar ao povo um preso, aquele que quisessem.' },
    { v: 16, en: 'And they had then a notable prisoner, called Barabbas.', pt: 'E tinham então um preso célebre, chamado Barrabás.' },
    { v: 17, en: 'Therefore when they were gathered together, Pilate said unto them, Whom will ye that I release unto you? Barabbas, or Jesus which is called Christ?', pt: 'Estando eles reunidos, disse-lhes Pilatos: A quem quereis que eu vos solte: Barrabás, ou a Jesus, chamado o Cristo?' },
    { v: 18, en: 'For he knew that for envy they had delivered him.', pt: 'Porque sabia que por inveja o tinham entregado.' },
    { v: 19, en: 'When he was set down on the judgment seat, his wife sent unto him, saying, Have thou nothing to do with that just man: for I have suffered many things this day in a dream because of him.', pt: 'E, estando ele assentado no tribunal, sua mulher mandou dizer-lhe: Não te metas com esse justo, porque hoje padeci muito em sonho por causa dele.' },
    { v: 20, en: 'But the chief priests and elders persuaded the multitude that they should ask Barabbas, and destroy Jesus.', pt: 'E os principais sacerdotes e os anciãos persuadiram as multidões a que pedissem Barrabás e fizessem morrer Jesus.' },
    { v: 21, en: 'The governor answered and said unto them, Whether of the twain will ye that I release unto you? They said, Barabbas.', pt: 'E o governador, respondendo, disse-lhes: Qual dos dois quereis que vos solte? E eles disseram: Barrabás.' },
    { v: 22, en: 'Pilate saith unto them, What shall I do then with Jesus which is called Christ? They all say unto him, Let him be crucified.', pt: 'Disse-lhes Pilatos: Que farei, pois, de Jesus, chamado o Cristo? Disseram todos: Seja crucificado.' },
    { v: 23, en: 'And the governor said, Why, what evil hath he done? But they cried out the more, saying, Let him be crucified.', pt: 'E ele disse: Que mal fez ele? Mas eles clamavam cada vez mais: Seja crucificado.' },
    { v: 24, en: 'When Pilate saw that he could prevail nothing, but that rather a tumult was made, he took water, and washed his hands before the multitude, saying, I am innocent of the blood of this just person: see ye to it.', pt: 'E Pilatos, vendo que nada conseguia, antes que o tumulto aumentava, tomou água e lavou as mãos diante da multidão, dizendo: Estou inocente do sangue deste justo; vós o vereis.' },
    { v: 25, en: 'Then answered all the people, and said, His blood be on us, and on our children.', pt: 'E todo o povo respondeu: O seu sangue caia sobre nós e sobre nossos filhos.' },
    { v: 26, en: 'Then released he Barabbas unto them: and when he had scourged Jesus, he delivered him to be crucified.', pt: 'Então soltou-lhes Barrabás; e, depois de açoitar Jesus, entregou-o para ser crucificado.' },
    { v: 27, en: 'Then the soldiers of the governor took Jesus into the common hall, and gathered unto him the whole band of soldiers.', pt: 'Então os soldados do governador levaram Jesus para dentro do pretório e reuniram em torno dele toda a coorte.' },
    { v: 28, en: 'And they stripped him, and put on him a scarlet robe.', pt: 'E, despindo-o, puseram-lhe uma capa escarlate.' },
    { v: 29, en: 'And when they had platted a crown of thorns, they put it upon his head, and a reed in his right hand: and they bowed the knee before him, and mocked him, saying, Hail, King of the Jews!', pt: 'E, tecendo uma coroa de espinhos, puseram-lha na cabeça e uma cana na sua mão direita; e, ajoelhando diante dele, o escarneciam, dizendo: Salve, Rei dos judeus!' },
    { v: 30, en: 'And they spit upon him, and took the reed, and smote him on the head.', pt: 'E, cuspindo nele, tomaram a cana e o batiam na cabeça.' },
    { v: 31, en: 'And after that they had mocked him, they took the robe off from him, and put his own raiment on him, and led him away to crucify him.', pt: 'E, depois de o escarneceram, tiraram-lhe a capa, vestiram-lhe as suas próprias vestes e o levaram para crucificar.' },
    { v: 32, en: 'And as they came out, they found a man of Cyrene, Simon by name: him they compelled to bear his cross.', pt: 'E, ao saírem, encontraram um homem de Cirene, chamado Simão, a quem obrigaram a carregar a sua cruz.' },
    { v: 33, en: 'And when they were come unto a place called Golgotha, that is to say, a place of a skull,', pt: 'E, chegando a um lugar chamado Gólgota, que significa lugar da Caveira,' },
    { v: 34, en: 'They gave him vinegar to drink mingled with gall: and when he had tasted thereof, he would not drink.', pt: 'deram-lhe a beber vinagre misturado com fel; e ele, provando-o, não quis beber.' },
    { v: 35, en: 'And they crucified him, and parted his garments, casting lots: that it might be fulfilled which was spoken by the prophet, They parted my garments among them, and upon my vesture did they cast lots.', pt: 'E, havendo-o crucificado, repartiram as suas vestes, lançando sortes; para que se cumprisse o que foi dito pelo profeta: Repartiram entre si as minhas vestes, e sobre a minha roupa lançaram sortes.' },
    { v: 36, en: 'And sitting down they watched him there;', pt: 'E, assentando-se, o guardavam ali.' },
    { v: 37, en: 'And set up over his head his accusation written, THIS IS JESUS THE KING OF THE JEWS.', pt: 'E puseram por cima da sua cabeça a sua acusação escrita: ESTE É JESUS, O REI DOS JUDEUS.' },
    { v: 38, en: 'Then were there two thieves crucified with him, one on the right hand, and another on the left.', pt: 'Então foram crucificados com ele dois ladrões, um à direita e outro à esquerda.' },
    { v: 39, en: 'And they that passed by reviled him, wagging their heads,', pt: 'E os que passavam o injuriavam, meneando a cabeça' },
    { v: 40, en: 'And saying, Thou that destroyest the temple, and buildest it in three days, save thyself. If thou be the Son of God, come down from the cross.', pt: 'e dizendo: Tu que destróis o templo e o reedificas em três dias, salva-te a ti mesmo; se és Filho de Deus, desce da cruz.' },
    { v: 41, en: 'Likewise also the chief priests mocking him, with the scribes and elders, said,', pt: 'Da mesma forma também os principais sacerdotes, com os escribas e os anciãos, escarnecendo, diziam:' },
    { v: 42, en: 'He saved others; himself he cannot save. If he be the King of Israel, let him now come down from the cross, and we will believe him.', pt: 'Aos outros salvou, a si mesmo não pode salvar. Se é o Rei de Israel, desça agora da cruz, e nele creremos.' },
    { v: 43, en: 'He trusted in God; let him deliver him now, if he will have him: for he said, I am the Son of God.', pt: 'Confiou em Deus; livre-o agora, se o quer; porque disse: Sou o Filho de Deus.' },
    { v: 44, en: 'The thieves also, which were crucified with him, cast the same in his teeth.', pt: 'O mesmo também lhe diziam os ladrões que com ele estavam crucificados.' },
    { v: 45, en: 'Now from the sixth hour there was darkness over all the land unto the ninth hour.', pt: 'E desde a hora sexta até à hora nona houve trevas sobre toda a terra.' },
    { v: 46, en: 'And about the ninth hour Jesus cried with a loud voice, saying, Eli, Eli, lama sabachthani? that is to say, My God, my God, why hast thou forsaken me?', pt: 'E por volta da hora nona exclamou Jesus com uma grande voz: Eli, Eli, lamá sabactâni? que quer dizer: Deus meu, Deus meu, por que me abandonaste?' },
    { v: 47, en: 'Some of them that stood there, when they heard that, said, This man calleth for Elias.', pt: 'E alguns dos que ali estavam, ouvindo isso, diziam: Este chama por Elias.' },
    { v: 48, en: 'And straightway one of them ran, and took a spunge, and filled it with vinegar, and put it on a reed, and gave him to drink.', pt: 'E logo um deles correu, tomou uma esponja, encheu-a de vinagre e, pondo-a numa cana, deu-lhe a beber.' },
    { v: 49, en: 'The rest said, Let be, let us see whether Elias will come to save him.', pt: 'Os outros diziam: Deixa, vejamos se Elias vem salvá-lo.' },
    { v: 50, en: 'Jesus, when he had cried again with a loud voice, yielded up the ghost.', pt: 'E Jesus, havendo clamado de novo com uma grande voz, entregou o espírito.' },
    { v: 51, en: 'And, behold, the veil of the temple was rent in twain from the top to the bottom; and the earth did quake, and the rocks rent;', pt: 'E eis que o véu do templo se rasgou em dois, de alto a baixo; e a terra tremeu, e as pedras se fenderam;' },
    { v: 52, en: 'And the graves were opened; and many bodies of the saints which slept arose,', pt: 'e os sepulcros se abriram; e muitos corpos de santos que dormiam foram ressuscitados,' },
    { v: 53, en: 'And came out of the graves after his resurrection, and went into the holy city, and appeared unto many.', pt: 'e, saindo dos sepulcros depois da sua ressurreição, entraram na cidade santa e apareceram a muitos.' },
    { v: 54, en: 'Now when the centurion, and they that were with him, watching Jesus, saw the earthquake, and those things that were done, they feared greatly, saying, Truly this was the Son of God.', pt: 'E o centurião e os que estavam com ele guardando Jesus, vendo o tremor de terra e as coisas que tinham acontecido, ficaram com muito temor e disseram: Verdadeiramente este era o Filho de Deus.' },
    { v: 55, en: 'And many women were there beholding afar off, which followed Jesus from Galilee, ministering unto him:', pt: 'E estavam ali muitas mulheres, olhando de longe, as quais tinham seguido Jesus desde a Galileia, servindo-o;' },
    { v: 56, en: 'Among which was Mary Magdalene, and Mary the mother of James and Joses, and the mother of Zebedee\'s children.', pt: 'entre as quais estavam Maria Madalena, e Maria, mãe de Tiago e de José, e a mãe dos filhos de Zebedeu.' },
    { v: 57, en: 'When the even was come, there came a rich man of Arimathaea, named Joseph, who also himself was Jesus\' disciple:', pt: 'E, chegada a tarde, veio um homem rico de Arimateia, por nome José, que também era discípulo de Jesus.' },
    { v: 58, en: 'He went to Pilate, and begged the body of Jesus. Then Pilate commanded the body to be delivered.', pt: 'Este foi ter com Pilatos e pediu o corpo de Jesus. Então Pilatos ordenou que o corpo lhe fosse entregue.' },
    { v: 59, en: 'And when Joseph had taken the body, he wrapped it in a clean linen cloth,', pt: 'E José, tomando o corpo, envolveu-o num pano de linho limpo' },
    { v: 60, en: 'And laid it in his own new tomb, which he had hewn out in the rock: and he rolled a great stone to the door of the sepulchre, and departed.', pt: 'e o depositou no seu próprio sepulcro novo, que havia aberto na rocha; e, rolando uma grande pedra para a porta do sepulcro, retirou-se.' },
    { v: 61, en: 'And there was Mary Magdalene, and the other Mary, sitting over against the sepulchre.', pt: 'E estava ali Maria Madalena e a outra Maria, assentadas defronte do sepulcro.' },
    { v: 62, en: 'Now the next day, that followed the day of the preparation, the chief priests and Pharisees came together unto Pilate,', pt: 'E no dia seguinte, que era depois da preparação, os principais sacerdotes e os fariseus reuniram-se perante Pilatos,' },
    { v: 63, en: 'Saying, Sir, we remember that that deceiver said, while he was yet alive, After three days I will rise again.', pt: 'dizendo: Senhor, lembramo-nos de que aquele enganador disse, ainda em vida: Depois de três dias ressuscitarei.' },
    { v: 64, en: 'Command therefore that the sepulchre be made sure until the third day, lest his disciples come by night, and steal him away, and say unto the people, He is risen from the dead: so the last error shall be worse than the first.', pt: 'Ordena, pois, que o sepulcro seja guardado até ao terceiro dia, para que os seus discípulos não venham e o roubem, e digam ao povo: Ressuscitou dos mortos; e o último erro será pior do que o primeiro.' },
    { v: 65, en: 'Pilate said unto them, Ye have a watch: go your way, make it as sure as ye can.', pt: 'Pilatos disse-lhes: Tendes uma guarda; ide, guardai-o como souberdes.' },
    { v: 66, en: 'So they went, and made the sepulchre sure, sealing the stone, and setting a watch.', pt: 'E eles foram e guardaram o sepulcro, selando a pedra com a guarda.' },
  ],
  28: [
    { v: 1, en: 'In the end of the sabbath, as it began to dawn toward the first day of the week, came Mary Magdalene and the other Mary to see the sepulchre.', pt: 'E, terminado o sábado, ao amanhecer do primeiro dia da semana, vieram Maria Madalena e a outra Maria ver o sepulcro.' },
    { v: 2, en: 'And, behold, there was a great earthquake: for the angel of the Lord descended from heaven, and came and rolled back the stone from the door, and sat upon it.', pt: 'E eis que houve um grande terremoto, porque o anjo do Senhor desceu do céu e, chegando, revolveu a pedra e assentou-se sobre ela.' },
    { v: 3, en: 'His countenance was like lightning, and his raiment white as snow:', pt: 'E o seu aspecto era como um relâmpago, e o seu vestido branco como a neve.' },
    { v: 4, en: 'And for fear of him the keepers did shake, and became as dead men.', pt: 'E os guardas tremeram de medo dele e ficaram como mortos.' },
    { v: 5, en: 'And the angel answered and said unto the women, Fear not ye: for I know that ye seek Jesus, which was crucified.', pt: 'E o anjo, respondendo, disse às mulheres: Não temais vós; porque sei que buscais a Jesus, que foi crucificado.' },
    { v: 6, en: 'He is not here: for he is risen, as he said. Come, see the place where the Lord lay.', pt: 'Não está aqui; ressuscitou, como tinha dito. Vinde, vede o lugar onde o Senhor jazia.' },
    { v: 7, en: 'And go quickly, and tell his disciples that he is risen from the dead; and, behold, he goeth before you into Galilee; there shall ye see him: lo, I have told you.', pt: 'E ide depressa, dizei aos seus discípulos que ele ressuscitou dos mortos; e eis que ele vai adiante de vós para a Galileia; ali o vereis; eis que vo-lo disse.' },
    { v: 8, en: 'And they departed quickly from the sepulchre with fear and great joy; and did run to bring his disciples word.', pt: 'E elas partiram depressa do sepulcro, com temor e grande alegria, e correram a anunciar isso aos seus discípulos.' },
    { v: 9, en: 'And as they went to tell his disciples, behold, Jesus met them, saying, All hail. And they came and held him by the feet, and worshipped him.', pt: 'E eis que Jesus lhes saiu ao encontro, dizendo: Salve! E elas, aproximando-se, abraçaram-lhe os pés e o adoraram.' },
    { v: 10, en: 'Then said Jesus unto them, Be not afraid: go tell my brethren that they go into Galilee, and there shall they see me.', pt: 'Então Jesus lhes disse: Não temais; ide, anunciai aos meus irmãos que vão à Galileia, e lá me verão.' },
    { v: 11, en: 'Now when they were going, behold, some of the watch came into the city, and shewed unto the chief priests all the things that were done.', pt: 'E, enquanto elas iam, eis que alguns da guarda foram à cidade e anunciaram aos principais sacerdotes tudo o que tinha acontecido.' },
    { v: 12, en: 'And when they were assembled with the elders, and had taken counsel, they gave large money unto the soldiers,', pt: 'E estes, reunindo-se com os anciãos e deliberando, deram dinheiro em abundância aos soldados,' },
    { v: 13, en: 'Saying, Say ye, His disciples came by night, and stole him away while we slept.', pt: 'dizendo: Dizei: Os seus discípulos vieram de noite e o roubaram, enquanto nós dormíamos.' },
    { v: 14, en: 'And if this come to the governor\'s ears, we will persuade him, and secure you.', pt: 'E, se isso chegar aos ouvidos do governador, nós o persuadiremos e vos livraremos de qualquer aperto.' },
    { v: 15, en: 'So they took the money, and did as they were taught: and this saying is commonly reported among the Jews until this day.', pt: 'E eles, tomando o dinheiro, fizeram como foram ensinados; e esta palavra divulgou-se entre os judeus até ao dia de hoje.' },
    { v: 16, en: 'Then the eleven disciples went away into Galilee, into a mountain where Jesus had appointed them.', pt: 'E os onze discípulos foram para a Galileia, ao monte que Jesus lhes havia indicado.' },
    { v: 17, en: 'And when they saw him, they worshipped him: but some doubted.', pt: 'E, quando o viram, o adoraram; mas alguns duvidaram.' },
    { v: 18, en: 'And Jesus came and spake unto them, saying, All power is given unto me in heaven and in earth.', pt: 'E Jesus, aproximando-se, falou-lhes, dizendo: Todo o poder me foi dado no céu e na terra.' },
    { v: 19, en: 'Go ye therefore, and teach all nations, baptizing them in the name of the Father, and of the Son, and of the Holy Ghost:', pt: 'Portanto ide, e fazei discípulos de todas as nações, batizando-os em nome do Pai, e do Filho, e do Espírito Santo;' },
    { v: 20, en: 'Teaching them to observe all things whatsoever I have commanded you: and, lo, I am with you always, even unto the end of the world. Amen.', pt: 'ensinando-os a observar todas as coisas que eu vos tenho mandado; e eis que eu estou convosco todos os dias, até à consumação dos séculos. Amém.' },
  ],
};
